// Java OOP — 260 Questions
export const OOP_Q = [
  { id: "oop1", diff: "easy", topic: "Basics", q: "What does OOP stand for?", opts: ["Object Oriented Programming", "Object Oriented Protocol", "Ordered Object Programming", "Open Object Programming"], ans: 0, exp: "OOP stands for Object-Oriented Programming â€” a paradigm that organises software around objects (data + behaviour) rather than functions and logic." },
  { id: "oop2", diff: "easy", topic: "Basics", q: "Which of the following is NOT a pillar of OOP?", opts: ["Encapsulation", "Inheritance", "Compilation", "Polymorphism"], ans: 2, exp: "The four pillars of OOP are Encapsulation, Inheritance, Polymorphism, and Abstraction. Compilation is a build-process concept, not an OOP pillar." },
  { id: "oop3", diff: "easy", topic: "Class & Object", q: "What is a class in Java?", opts: ["A runtime instance", "A blueprint for creating objects", "A built-in data type", "A reserved keyword only"], ans: 1, exp: "A class is a template/blueprint that defines the properties (fields) and behaviours (methods) that its objects will have." },
  { id: "oop4", diff: "easy", topic: "Class & Object", q: "What is an object in Java?", opts: ["A keyword", "A primitive data type", "An instance of a class", "A method definition"], ans: 2, exp: "An object is a concrete instance of a class, created with the 'new' keyword. It occupies memory and has its own state." },
  { id: "oop5", diff: "easy", topic: "Class & Object", q: "Which keyword is used to create an object in Java?", opts: ["create", "object", "new", "make"], ans: 2, exp: "The 'new' keyword allocates memory on the heap for a new object and calls the constructor: MyClass obj = new MyClass();" },
  { id: "oop6", diff: "easy", topic: "Constructor", q: "What is a constructor in Java?", opts: ["A method that returns an object", "A special method called automatically when an object is created", "A static block", "A destructor method"], ans: 1, exp: "A constructor is a special method with the same name as the class, no return type, called automatically when 'new' is used to initialise the object." },
  { id: "oop7", diff: "easy", topic: "Constructor", q: "What is a default constructor?", opts: ["A constructor with parameters", "A constructor the compiler provides if none is defined", "A private constructor", "A static constructor"], ans: 1, exp: "If you write no constructor, Java provides a default no-arg constructor that initialises fields to default values (0, null, false)." },
  { id: "oop8", diff: "easy", topic: "Encapsulation", q: "Which access modifier makes a member accessible only within its own class?", opts: ["public", "protected", "default", "private"], ans: 3, exp: "'private' restricts access to the declaring class only. This is the core of encapsulation â€” hiding internal state." },
  { id: "oop9", diff: "easy", topic: "Encapsulation", q: "What are getter and setter methods used for?", opts: ["To delete objects", "To provide controlled access to private fields", "To override methods", "To define constructors"], ans: 1, exp: "Getters/setters allow read/write access to private fields while enabling validation, logging, or other logic â€” a key encapsulation technique." },
  { id: "oop10", diff: "easy", topic: "Inheritance", q: "Which keyword is used to inherit a class in Java?", opts: ["implements", "inherits", "extends", "super"], ans: 2, exp: "The 'extends' keyword establishes an IS-A relationship: class Dog extends Animal means Dog inherits all non-private members of Animal." },
  { id: "oop11", diff: "easy", topic: "Inheritance", q: "What is the parent class also called?", opts: ["Child class", "Derived class", "Super class", "Sub class"], ans: 2, exp: "The parent/base class is called the superclass. The child/derived class is called the subclass. 'super' keyword refers to the superclass." },
  { id: "oop12", diff: "easy", topic: "Inheritance", q: "Does Java support multiple inheritance through classes?", opts: ["Yes, always", "No, not through classes", "Yes, with 'extends' multiple", "Only in abstract classes"], ans: 1, exp: "Java does NOT support multiple class inheritance to avoid the 'diamond problem'. However, a class can implement multiple interfaces." },
  { id: "oop13", diff: "easy", topic: "Polymorphism", q: "What does polymorphism mean?", opts: ["Single form", "Many forms", "No form", "Static form"], ans: 1, exp: "Polymorphism (Greek: 'many forms') allows the same method name to behave differently based on context â€” at compile time (overloading) or runtime (overriding)." },
  { id: "oop14", diff: "easy", topic: "Polymorphism", q: "Which type of polymorphism is method overloading?", opts: ["Runtime polymorphism", "Dynamic polymorphism", "Compile-time polymorphism", "Interface polymorphism"], ans: 2, exp: "Method overloading is resolved at compile time (static binding) based on method signature â€” number, type, or order of parameters." },
  { id: "oop15", diff: "easy", topic: "Polymorphism", q: "Which type of polymorphism is method overriding?", opts: ["Compile-time polymorphism", "Static polymorphism", "Runtime polymorphism", "Early binding"], ans: 2, exp: "Method overriding is resolved at runtime (dynamic dispatch / late binding) based on the actual object type, not the reference type." },
  { id: "oop16", diff: "easy", topic: "Abstraction", q: "Which keyword is used to define an abstract class?", opts: ["interface", "virtual", "abstract", "static"], ans: 2, exp: "The 'abstract' keyword declares a class that cannot be instantiated and may contain abstract methods (declared without body)." },
  { id: "oop17", diff: "easy", topic: "Abstraction", q: "Can you instantiate an abstract class?", opts: ["Yes", "No", "Only with new keyword", "Only inside the same package"], ans: 1, exp: "Abstract classes cannot be instantiated directly. They must be subclassed, and the subclass must implement all abstract methods (or also be abstract)." },
  { id: "oop18", diff: "easy", topic: "Interface", q: "Which keyword is used to define an interface?", opts: ["abstract", "class", "interface", "implements"], ans: 2, exp: "The 'interface' keyword defines a contract â€” a set of method signatures that implementing classes must provide." },
  { id: "oop19", diff: "easy", topic: "Interface", q: "Which keyword does a class use to implement an interface?", opts: ["extends", "implements", "uses", "interface"], ans: 1, exp: "A class uses 'implements' to adopt an interface contract. It can implement multiple interfaces: class MyClass implements A, B, C {}" },
  { id: "oop20", diff: "easy", topic: "Interface", q: "Before Java 8, could interfaces have method bodies?", opts: ["Yes, always", "No, only abstract methods", "Yes, for static methods", "Yes, for private methods"], ans: 1, exp: "Before Java 8, interfaces could only have public abstract methods and public static final constants. Java 8 added default and static methods with bodies." },
  { id: "oop21", diff: "easy", topic: "Basics", q: "What is the 'this' keyword in Java?", opts: ["Refers to the superclass", "Refers to the current object instance", "Refers to the static context", "Refers to the interface"], ans: 1, exp: "'this' is a reference to the current object â€” used to distinguish instance variables from parameters with the same name, or to chain constructors." },
  { id: "oop22", diff: "easy", topic: "Basics", q: "What is the 'super' keyword used for?", opts: ["Reference current object", "Call child class method", "Reference the immediate superclass or its constructor/method", "Create static context"], ans: 2, exp: "'super' references the immediate parent class. Used as super() to call parent constructor, or super.method() to call an overridden parent method." },
  { id: "oop23", diff: "easy", topic: "Inheritance", q: "What is method overriding?", opts: ["Defining multiple methods with the same name", "Providing a new implementation in a subclass for a method defined in the superclass", "Creating abstract methods", "Hiding a method with static"], ans: 1, exp: "Method overriding re-implements a superclass method in a subclass with the same signature. The @Override annotation is recommended to catch errors at compile time." },
  { id: "oop24", diff: "easy", topic: "Polymorphism", q: "What is method overloading?", opts: ["Defining the same method in a subclass", "Defining multiple methods with the same name but different parameter lists in the same class", "Overriding a superclass method", "Hiding a static method"], ans: 1, exp: "Overloading: same method name, different parameter lists (number, type, or order). Return type alone does NOT differentiate overloaded methods." },
  { id: "oop25", diff: "easy", topic: "Basics", q: "What is a package in Java?", opts: ["A class", "A namespace that organises related classes and interfaces", "A method group", "A reserved keyword"], ans: 1, exp: "A package is a namespace mechanism that groups related classes/interfaces, avoids naming conflicts, and controls access with package-private visibility." },
  { id: "oop26", diff: "easy", topic: "Basics", q: "Which access modifier allows access from any class?", opts: ["private", "protected", "default", "public"], ans: 3, exp: "'public' allows access from any class in any package. Order from most restrictive: private < default < protected < public." },
  { id: "oop27", diff: "easy", topic: "Inheritance", q: "What does the 'final' keyword do when applied to a class?", opts: ["Makes it abstract", "Prevents it from being subclassed", "Makes all methods static", "Allows multiple inheritance"], ans: 1, exp: "A 'final' class cannot be extended/inherited (e.g., String, Integer). This is used for security and immutability." },
  { id: "oop28", diff: "easy", topic: "Inheritance", q: "What does 'final' do when applied to a method?", opts: ["Makes it abstract", "Prevents it from being overridden", "Makes it static", "Makes it private"], ans: 1, exp: "A 'final' method cannot be overridden in any subclass, ensuring its implementation remains unchanged throughout the hierarchy." },
  { id: "oop29", diff: "easy", topic: "Basics", q: "What is the root class of all Java classes?", opts: ["Class", "Object", "Base", "Root"], ans: 1, exp: "java.lang.Object is the root of the Java class hierarchy. Every class implicitly extends Object and inherits methods like equals(), hashCode(), toString()." },
  { id: "oop30", diff: "easy", topic: "Basics", q: "What is the purpose of the 'static' keyword on a field?", opts: ["Creates a new object for each field access", "Makes the field belong to the class rather than any instance", "Makes the field private", "Makes the field final"], ans: 1, exp: "Static fields (class variables) are shared across all instances. Only one copy exists regardless of how many objects are created." },
  { id: "oop31", diff: "easy", topic: "Basics", q: "Can a static method access instance variables directly?", opts: ["Yes", "No", "Only if they are final", "Only in the same package"], ans: 1, exp: "Static methods belong to the class, not an instance. They cannot directly access instance variables or call instance methods (no 'this' available)." },
  { id: "oop32", diff: "easy", topic: "Constructor", q: "Can a constructor be private?", opts: ["No", "Yes", "Only in abstract classes", "Only in interfaces"], ans: 1, exp: "Yes â€” private constructors are used in Singleton pattern, utility classes, and factory methods to control object creation." },
  { id: "oop33", diff: "easy", topic: "Constructor", q: "What is constructor chaining?", opts: ["Calling constructors of multiple classes", "Calling one constructor from another constructor in the same or parent class", "Overriding constructors", "Defining multiple constructors"], ans: 1, exp: "Constructor chaining: using this() to call another constructor in the same class, or super() to call a parent constructor. Must be the first statement." },
  { id: "oop34", diff: "easy", topic: "Interface", q: "What access modifier are interface methods by default (before Java 8)?", opts: ["private", "protected", "public abstract", "static"], ans: 2, exp: "Interface methods are implicitly 'public abstract' before Java 8. You don't need to write these modifiers â€” the compiler adds them automatically." },
  { id: "oop35", diff: "easy", topic: "Interface", q: "What type are interface variables/fields by default?", opts: ["private static", "public static final", "protected abstract", "default transient"], ans: 1, exp: "Interface fields are implicitly 'public static final' â€” they are constants. You must initialise them when declared." },
  { id: "oop36", diff: "easy", topic: "Abstraction", q: "What is the difference between abstract class and interface (pre-Java 8)?", opts: ["No difference", "Abstract class can have concrete methods and state; interface can only have abstract methods and constants", "Interface can extend classes", "Abstract class cannot have constructors"], ans: 1, exp: "Abstract class: can have constructors, instance fields, concrete methods, and abstract methods. Interface: only public abstract methods and public static final constants (pre-Java 8)." },
  { id: "oop37", diff: "easy", topic: "Encapsulation", q: "Which OOP principle does data hiding implement?", opts: ["Polymorphism", "Inheritance", "Encapsulation", "Abstraction"], ans: 2, exp: "Data hiding â€” making fields private and accessing via methods â€” is the core mechanism of encapsulation, protecting object state from external corruption." },
  { id: "oop38", diff: "easy", topic: "Basics", q: "What is a local variable?", opts: ["A variable declared inside a method or block", "A variable shared across all instances", "A variable declared with static", "A variable in an interface"], ans: 0, exp: "Local variables are declared inside methods, constructors, or blocks. They exist only during that scope's execution and must be explicitly initialised before use." },
  { id: "oop39", diff: "easy", topic: "Basics", q: "What is an instance variable?", opts: ["A variable declared inside a method", "A variable declared in a class but outside any method", "A static variable", "A variable in an interface"], ans: 1, exp: "Instance variables are declared in a class but outside methods. Each object gets its own copy, initialised to default values if not set explicitly." },
  { id: "oop40", diff: "easy", topic: "Polymorphism", q: "What is upcasting in Java?", opts: ["Converting subclass reference to superclass type", "Converting superclass to subclass", "Casting between unrelated classes", "Casting primitives to objects"], ans: 0, exp: "Upcasting: assigning a subclass object to a superclass reference â€” implicit and safe. e.g., Animal a = new Dog(); The Dog IS-AN Animal." },
  { id: "oop41", diff: "easy", topic: "Polymorphism", q: "What is downcasting?", opts: ["Converting superclass reference to subclass type", "Converting subclass to superclass", "Automatic casting", "Casting to interface"], ans: 0, exp: "Downcasting: explicitly casting a superclass reference back to the subclass type. Can throw ClassCastException if the actual object is not of that subclass." },
  { id: "oop42", diff: "easy", topic: "Basics", q: "What does 'instanceof' operator do?", opts: ["Creates an object", "Tests if an object is an instance of a class or interface", "Compares two objects", "Checks if a class is abstract"], ans: 1, exp: "'instanceof' returns true if the object is an instance of the specified class, subclass, or interface. Useful before downcasting to prevent ClassCastException." },
  { id: "oop43", diff: "easy", topic: "Inheritance", q: "How many classes can a Java class directly extend?", opts: ["Unlimited", "Two", "One", "Three"], ans: 2, exp: "Java supports single inheritance for classes â€” a class can extend only ONE other class. This avoids the diamond problem. Multiple inheritance is achieved via interfaces." },
  { id: "oop44", diff: "easy", topic: "Interface", q: "How many interfaces can a Java class implement?", opts: ["Only one", "Only two", "Any number", "Only three"], ans: 2, exp: "A class can implement any number of interfaces, providing Java's way to achieve multiple inheritance of type: class C implements A, B, D {}" },
  { id: "oop45", diff: "easy", topic: "Basics", q: "What is a wrapper class?", opts: ["A class that wraps a method", "A class that provides object representation of primitive types", "A class that extends Object", "A utility class"], ans: 1, exp: "Wrapper classes (Integer, Double, Boolean, etc.) wrap primitives into objects, enabling them to be used in collections, generics, and APIs that require objects." },
  { id: "oop46", diff: "easy", topic: "Basics", q: "What is autoboxing?", opts: ["Manual conversion of primitive to wrapper", "Automatic conversion of primitive to wrapper class object", "Converting a wrapper to String", "Creating an array of wrappers"], ans: 1, exp: "Autoboxing automatically converts a primitive (int) to its wrapper (Integer) when needed. Unboxing is the reverse. Introduced in Java 5." },
  { id: "oop47", diff: "easy", topic: "Basics", q: "What is the purpose of the 'toString()' method?", opts: ["Compares two objects", "Returns a string representation of the object", "Converts a class to interface", "Creates a copy of the object"], ans: 1, exp: "toString() is defined in Object and returns a string representation. Override it to provide meaningful output instead of the default hashCode-based string." },
  { id: "oop48", diff: "easy", topic: "Basics", q: "What does the 'equals()' method do by default (from Object)?", opts: ["Compares field values", "Compares object references (memory addresses)", "Compares hash codes", "Compares class names"], ans: 1, exp: "Object.equals() checks reference equality (==). Override it to compare field values for logical equality (e.g., String overrides it to compare character sequences)." },
  { id: "oop49", diff: "easy", topic: "Basics", q: "What is 'null' in Java?", opts: ["An empty string", "A zero integer", "A special literal meaning 'no object reference'", "A boolean false"], ans: 2, exp: "null is a special literal that can be assigned to any reference type, indicating the variable points to no object. Calling a method on null throws NullPointerException." },
  { id: "oop50", diff: "easy", topic: "Interface", q: "Can an interface extend another interface?", opts: ["No", "Yes, using implements", "Yes, using extends", "Only abstract interfaces"], ans: 2, exp: "Interfaces extend other interfaces using 'extends' (not implements). An interface can extend multiple interfaces: interface C extends A, B {}" },
  { id: "oop51", diff: "easy", topic: "Basics", q: "What is a static initializer block?", opts: ["A block that runs each time an object is created", "A block that runs once when the class is loaded", "A block inside a constructor", "A method with no return type"], ans: 1, exp: "A static { } block runs once when the class is first loaded by the JVM, before any objects are created. Used to initialise static variables with complex logic." },
  { id: "oop52", diff: "easy", topic: "Basics", q: "What is an instance initializer block?", opts: ["A block that runs once per class load", "A block that runs before every constructor call", "A block that replaces constructors", "A static block"], ans: 1, exp: "An instance initializer block { } (without static) runs before the constructor body every time an object is created. Useful for code shared across multiple constructors." },
  { id: "oop53", diff: "easy", topic: "Inheritance", q: "What is multilevel inheritance?", opts: ["A class extending multiple classes", "A chain where A extends B and B extends C", "Interfaces extending interfaces", "A class implementing multiple interfaces"], ans: 1, exp: "Multilevel inheritance: a chain A â†’ B â†’ C where C extends B which extends A. Java fully supports this via the single-inheritance chain." },
  { id: "oop54", diff: "easy", topic: "Inheritance", q: "What is hierarchical inheritance?", opts: ["Multiple classes extending the same parent", "One class extending multiple parents", "A chain of single extension", "Interfaces only"], ans: 0, exp: "Hierarchical inheritance: multiple classes (Dog, Cat, Bird) all extending the same base class (Animal). One parent, many children." },
  { id: "oop55", diff: "easy", topic: "Abstraction", q: "What is the purpose of abstraction in OOP?", opts: ["Hiding implementation details and exposing only essential features", "Making all methods static", "Preventing class creation", "Allowing multiple inheritance"], ans: 0, exp: "Abstraction hides complexity â€” users interact with a simple interface without knowing the internal implementation. Like driving a car without knowing the engine internals." },
  { id: "oop56", diff: "easy", topic: "Basics", q: "What is the difference between '==' and '.equals()' for String comparison?", opts: ["No difference", "== compares values, equals() compares references", "== compares references, equals() compares content", "Both compare references"], ans: 2, exp: "== for Strings checks reference equality (same object in memory). .equals() checks content equality (same characters). Always use .equals() for String value comparison." },
  { id: "oop57", diff: "easy", topic: "Basics", q: "What is a copy constructor?", opts: ["A constructor that makes the class final", "A constructor that creates a new object as a copy of another", "A constructor with no arguments", "A constructor for static classes"], ans: 1, exp: "A copy constructor takes an object of the same class as parameter and creates a new object with the same field values â€” a way to implement cloning." },
  { id: "oop58", diff: "easy", topic: "Basics", q: "Can we override static methods in Java?", opts: ["Yes", "No â€” static methods belong to the class, not instances", "Yes, but only in final classes", "Yes, with the @Override annotation"], ans: 1, exp: "Static methods cannot be overridden â€” they can be re-declared (method hiding), but the call is resolved at compile time based on the reference type, not runtime type." },
  { id: "oop59", diff: "easy", topic: "Basics", q: "What is the 'final' keyword when applied to a variable?", opts: ["Makes it static", "Makes it a constant â€” its value cannot be changed after initialisation", "Makes it abstract", "Makes it transient"], ans: 1, exp: "A 'final' variable is a constant. For primitives, the value can't change. For references, the reference can't change (though the object's state can, unless it's immutable)." },
  { id: "oop60", diff: "easy", topic: "Interface", q: "What is a functional interface?", opts: ["An interface with multiple methods", "An interface with exactly one abstract method", "An interface that extends Runnable", "An interface with only static methods"], ans: 1, exp: "A functional interface has exactly one abstract method (SAM â€” Single Abstract Method). Used as the basis for lambda expressions. Annotated with @FunctionalInterface (optional but recommended)." },
  { id: "oop61", diff: "easy", topic: "Basics", q: "What does JVM stand for?", opts: ["Java Variable Machine", "Java Virtual Machine", "Java Version Manager", "Java Visual Modifier"], ans: 1, exp: "JVM (Java Virtual Machine) executes Java bytecode. It provides platform independence â€” the same .class file runs on any OS with a JVM implementation." },
  { id: "oop62", diff: "easy", topic: "Basics", q: "What is the purpose of the 'hashCode()' method?", opts: ["Compare two objects", "Returns an integer hash for use in hash-based collections (HashMap, HashSet)", "Converts object to String", "Creates a copy of object"], ans: 1, exp: "hashCode() returns an integer representing the object, used to bucket it in hash tables. The contract: equal objects must have equal hash codes. Override hashCode() whenever you override equals()." },
  { id: "oop63", diff: "easy", topic: "Polymorphism", q: "What is dynamic method dispatch?", opts: ["Calling static methods dynamically", "The mechanism by which a call to an overridden method is resolved at runtime based on actual object type", "Calling interface methods", "Method overloading resolution"], ans: 1, exp: "Dynamic method dispatch (virtual method invocation): when a superclass reference holds a subclass object, the subclass's overridden method is called at runtime. Core of runtime polymorphism." },
  { id: "oop64", diff: "easy", topic: "Basics", q: "What is the 'protected' access modifier?", opts: ["Accessible only within class", "Accessible within same package and subclasses", "Accessible everywhere", "Accessible only through interfaces"], ans: 1, exp: "'protected' allows access within the same package and in subclasses (even in different packages). Useful for methods meant to be used/overridden by subclasses." },
  { id: "oop65", diff: "easy", topic: "Interface", q: "What is a marker interface?", opts: ["An interface with one method", "An interface with only constants", "An interface with no methods or fields â€” used to mark/tag a class", "A deprecated interface type"], ans: 2, exp: "Marker interfaces (Serializable, Cloneable, Remote) have no methods â€” they tag/mark a class, allowing the JVM or frameworks to identify and treat them specially." },
  { id: "oop66", diff: "easy", topic: "Basics", q: "What is the difference between a class and an object?", opts: ["No difference", "Class is an instance; object is a template", "Class is a blueprint; object is an instance of that blueprint", "Class is runtime; object is compile-time"], ans: 2, exp: "Class = design blueprint (exists once in memory as a type). Object = concrete instance (can have many) created from the blueprint with its own state." },
  { id: "oop67", diff: "easy", topic: "Basics", q: "What happens when you don't define any constructor in Java?", opts: ["Compile error", "The class cannot be used", "Java provides a default no-arg constructor", "A runtime exception is thrown"], ans: 2, exp: "The Java compiler automatically inserts a public no-arg default constructor that calls super(). This is removed once you define any constructor yourself." },
  { id: "oop68", diff: "easy", topic: "Encapsulation", q: "What is the benefit of encapsulation?", opts: ["Increases execution speed", "Prevents code reuse", "Protects data integrity and hides implementation details", "Allows multiple inheritance"], ans: 2, exp: "Encapsulation bundles data and methods, prevents direct external access to internal state, enforces invariants via validation in setters, and allows implementation changes without breaking callers." },
  { id: "oop69", diff: "easy", topic: "Inheritance", q: "What is the IS-A relationship?", opts: ["Composition relationship", "Inheritance relationship â€” a subclass IS-A type of its superclass", "Association relationship", "Aggregation relationship"], ans: 1, exp: "IS-A represents inheritance: Dog IS-AN Animal. Test: can you substitute a Dog wherever an Animal is expected? If yes, IS-A is appropriate. This is the Liskov Substitution Principle foundation." },
  { id: "oop70", diff: "easy", topic: "Basics", q: "What is the HAS-A relationship?", opts: ["Inheritance relationship", "Composition or aggregation â€” one class contains a reference to another", "Interface implementation", "Static relationship"], ans: 1, exp: "HAS-A represents composition/aggregation: Car HAS-AN Engine. Prefer composition over inheritance when the relationship is 'has' rather than 'is'. More flexible and less coupled." },
  { id: "oop71", diff: "medium", topic: "Polymorphism", q: "What is covariant return type in method overriding?", opts: ["Returning a broader type", "Returning the same type always", "Returning a subtype of the return type declared in the overridden method", "Returning void always"], ans: 2, exp: "Since Java 5, an overriding method can return a subtype of the original return type. e.g., parent returns Animal, child can return Dog (a subtype). Makes overriding more flexible." },
  { id: "oop72", diff: "medium", topic: "Polymorphism", q: "Can we override the equals() and hashCode() methods?", opts: ["No, they are final", "Yes, and it's often required for correct behaviour in collections", "Only equals() can be overridden", "Only hashCode() can be overridden"], ans: 1, exp: "Yes â€” and both must be overridden together (contract). If equals() returns true for two objects, their hashCode() must be equal, otherwise HashMap/HashSet will behave incorrectly." },
  { id: "oop73", diff: "medium", topic: "Inheritance", q: "What is the diamond problem in multiple inheritance?", opts: ["A compiler error in single inheritance", "Ambiguity when a class inherits the same method from two parents that both inherited from a common ancestor", "A NullPointerException pattern", "A memory leak pattern"], ans: 1, exp: "If D extends B and C, and B and C both override method from A, which version does D inherit? Java avoids this for classes (single inheritance). Interfaces handle it with default method resolution rules." },
  { id: "oop74", diff: "medium", topic: "Interface", q: "What is a default method in an interface (Java 8+)?", opts: ["A method that does nothing", "A method with a body in an interface, providing a default implementation", "A private method", "An overridable abstract method"], ans: 1, exp: "Java 8 'default' methods have an implementation in the interface itself. Implementing classes inherit the default implementation unless they override it. Enables adding methods to interfaces without breaking existing implementations." },
  { id: "oop75", diff: "medium", topic: "Interface", q: "If a class implements two interfaces that both have the same default method, what must the class do?", opts: ["Nothing â€” Java picks automatically", "Override the method to resolve the ambiguity", "Implement only one interface", "Throw a compile error at runtime"], ans: 1, exp: "A compile-time error occurs if a class inherits conflicting default methods without overriding. The class MUST override the method to resolve ambiguity, optionally calling Interface.super.method()." },
  { id: "oop76", diff: "medium", topic: "Abstraction", q: "Can an abstract class have a constructor?", opts: ["No", "Yes, called by subclass constructors via super()", "Only if it has no abstract methods", "Only private constructors"], ans: 1, exp: "Abstract classes CAN have constructors. They are called when a subclass is instantiated (via super()). Useful for initialising common fields in the abstract class." },
  { id: "oop77", diff: "medium", topic: "Abstraction", q: "What happens if a subclass does not implement all abstract methods of the parent?", opts: ["Runtime exception", "Compile-time error unless the subclass is also declared abstract", "Nothing â€” they are skipped", "The class uses default implementations"], ans: 1, exp: "If a concrete class doesn't implement all abstract methods, the compiler throws an error. If it's declared abstract itself, it can defer implementation to further subclasses." },
  { id: "oop78", diff: "medium", topic: "Basics", q: "What is the contract between equals() and hashCode()?", opts: ["No contract exists", "If two objects are equal (equals() = true), they must have the same hashCode", "If two objects have the same hashCode, they must be equal", "hashCode() must always return 0"], ans: 1, exp: "Java contract: equals() = true â†’ same hashCode(). Reverse is NOT required (hash collision is allowed). Violating this breaks HashMap, HashSet, and any hash-based collection." },
  { id: "oop79", diff: "medium", topic: "Design", q: "What is the Singleton design pattern?", opts: ["A class with only static methods", "A pattern ensuring only one instance of a class exists", "A pattern creating many objects", "An inheritance pattern"], ans: 1, exp: "Singleton ensures a class has exactly one instance with global access. Implemented via private constructor, static instance field, and a static getInstance() method. Thread-safety requires synchronisation or the initialise-on-demand holder pattern." },
  { id: "oop80", diff: "medium", topic: "Design", q: "What pattern does the following describe: An abstract creator class with a method that subclasses override to create objects?", opts: ["Singleton", "Factory Method", "Observer", "Strategy"], ans: 1, exp: "Factory Method: defines an interface for creating an object but lets subclasses decide which class to instantiate. Promotes loose coupling between creation logic and usage." },
  { id: "oop81", diff: "medium", topic: "Polymorphism", q: "What is the output of calling an overridden method via a superclass reference? Animal a = new Dog(); a.sound();", opts: ["Always calls Animal's sound()", "Always calls Dog's sound()", "Compile error", "Depends on the cast"], ans: 1, exp: "Runtime polymorphism: the actual object type (Dog) determines which method runs, not the reference type (Animal). This is the power of dynamic dispatch." },
  { id: "oop82", diff: "medium", topic: "Basics", q: "What is object cloning in Java?", opts: ["Creating a new class", "Creating a copy of an existing object", "Converting object to String", "Serializing an object"], ans: 1, exp: "Object cloning creates a copy of an object. Implement Cloneable (marker interface) and override clone(). Shallow clone copies field values; deep clone also clones referenced objects." },
  { id: "oop83", diff: "medium", topic: "Basics", q: "What is the difference between shallow copy and deep copy?", opts: ["No difference", "Shallow copy copies primitive fields; deep copy copies nothing", "Shallow copy copies references (shared objects); deep copy copies the entire object graph recursively", "Deep copy copies only primitives"], ans: 2, exp: "Shallow copy: a new object with the same field values â€” reference fields point to the SAME nested objects. Deep copy: a new object where reference fields point to NEW copies of the nested objects." },
  { id: "oop84", diff: "medium", topic: "Design", q: "What is the purpose of the Builder pattern?", opts: ["Build inheritance hierarchies", "Construct complex objects step by step, separating construction from representation", "Build interfaces dynamically", "Create singleton instances"], ans: 1, exp: "Builder separates construction of a complex object from its representation. Useful when an object has many optional parameters (avoids telescoping constructors). Used in StringBuilder, Lombok @Builder, AlertDialog.Builder." },
  { id: "oop85", diff: "medium", topic: "Inheritance", q: "What is method hiding in Java?", opts: ["Making a method private", "Defining a static method in a subclass with the same signature as a static method in the parent â€” resolved by reference type", "Overriding an instance method", "Preventing method access from other packages"], ans: 1, exp: "When a subclass defines a static method with the same signature as a parent's static method, it HIDES (not overrides) it. The call is resolved at compile time based on reference type, not runtime type." },
  { id: "oop86", diff: "medium", topic: "Basics", q: "What is the 'transient' keyword in Java?", opts: ["Makes a field static", "Prevents a field from being serialized", "Makes a field volatile", "Makes a field final"], ans: 1, exp: "'transient' fields are excluded from serialization. When an object is serialized to a stream, transient fields are skipped and restored to default values upon deserialization." },
  { id: "oop87", diff: "medium", topic: "Basics", q: "What is the 'volatile' keyword?", opts: ["Makes a variable constant", "Ensures all threads see the latest value of a variable (prevents caching in CPU registers/L1 cache)", "Makes a field transient", "Makes a method synchronized"], ans: 1, exp: "'volatile' ensures visibility: reads/writes of the variable go directly to main memory, not CPU cache. Doesn't guarantee atomicity (use AtomicInteger or synchronized for that)." },
  { id: "oop88", diff: "medium", topic: "Interface", q: "Can interfaces have static methods (Java 8+)?", opts: ["No", "Yes, and they cannot be overridden â€” called via InterfaceName.method()", "Yes, and they are inherited", "Yes, but only abstract static"], ans: 1, exp: "Java 8 allows 'static' methods in interfaces. Unlike default methods, they are NOT inherited by implementing classes and must be called via the interface name." },
  { id: "oop89", diff: "medium", topic: "Interface", q: "Can interfaces have private methods (Java 9+)?", opts: ["No", "Yes â€” to share code between default methods without exposing to implementing classes", "Yes, but only abstract", "Only in functional interfaces"], ans: 1, exp: "Java 9 introduced private methods in interfaces to allow code reuse between default methods, without exposing the helper logic to implementing classes." },
  { id: "oop90", diff: "medium", topic: "Design", q: "What is the Observer (Publisher-Subscriber) pattern?", opts: ["One object creates many", "An object (subject) maintains a list of dependents (observers) and notifies them automatically of state changes", "One object delegates to another", "Hiding implementation behind interface"], ans: 1, exp: "Observer: Subject maintains a list of Observer objects and calls their update() when state changes. Foundation of event systems, MVC, reactive programming, and Java's EventListener." },
  { id: "oop91", diff: "medium", topic: "Generics", q: "What are Java generics?", opts: ["Runtime type information", "A mechanism for parameterizing types (classes, interfaces, methods) to ensure type safety at compile time", "Dynamic casting", "Primitive type boxing"], ans: 1, exp: "Generics allow writing classes/methods that work with any type while maintaining compile-time type safety. e.g., List<String> ensures only Strings are added, eliminating casts and ClassCastExceptions." },
  { id: "oop92", diff: "medium", topic: "Generics", q: "What is type erasure in Java generics?", opts: ["Removing all code at runtime", "Generic type parameters are removed (erased) at compile time and replaced with Object or bounds â€” generics exist only at compile time", "Converting generics to primitives", "Deleting unused generic classes"], ans: 1, exp: "Type erasure: the compiler removes all generic type information before generating bytecode. List<String> and List<Integer> become just List at runtime. This maintains backward compatibility." },
  { id: "oop93", diff: "medium", topic: "Generics", q: "What is a bounded type parameter? Example: <T extends Comparable<T>>", opts: ["A type that must be a primitive", "A type parameter restricted to a class or its subclasses", "A type that cannot extend anything", "A fixed type parameter"], ans: 1, exp: "<T extends Comparable<T>> means T must implement Comparable. Upper bounded wildcard <? extends Number> accepts Number and subclasses. Lower bounded <? super Integer> accepts Integer and supertypes." },
  { id: "oop94", diff: "medium", topic: "Basics", q: "What is the difference between String, StringBuilder, and StringBuffer?", opts: ["No difference", "String is immutable; StringBuilder is mutable and not thread-safe; StringBuffer is mutable and thread-safe", "String is mutable; StringBuilder is immutable", "StringBuffer is faster than StringBuilder"], ans: 1, exp: "String: immutable (creates new object on modification). StringBuilder: mutable, not thread-safe, faster. StringBuffer: mutable, thread-safe (synchronized methods), slightly slower. Use StringBuilder in single-threaded code." },
  { id: "oop95", diff: "medium", topic: "Basics", q: "Why is String immutable in Java?", opts: ["Compiler limitation", "Security (passwords), String pool efficiency, thread safety, and hashCode caching", "Memory limitation", "Simplicity"], ans: 1, exp: "Immutability enables: (1) String pool sharing (interning), (2) thread safety, (3) security (credentials can't be changed after passing), (4) cached hashCode. A mutable String used as HashMap key would corrupt the map on modification." },
  { id: "oop96", diff: "medium", topic: "Basics", q: "What is the String pool (String intern pool)?", opts: ["A buffer for string output", "An area in the heap where String literals are cached and shared", "A sorted collection of Strings", "A thread-safe String queue"], ans: 1, exp: "String literals like 'hello' are stored in the String pool. If the same literal is used again, the same object is returned rather than creating a new one. This saves memory. String.intern() adds a string to the pool." },
  { id: "oop97", diff: "medium", topic: "Exception", q: "What is the difference between checked and unchecked exceptions?", opts: ["No difference", "Checked exceptions must be declared or handled at compile time; unchecked extend RuntimeException and don't require explicit handling", "Unchecked exceptions must be caught; checked don't", "Checked exceptions crash the JVM"], ans: 1, exp: "Checked (IOException, SQLException): compiler forces you to handle or declare them (throws). Unchecked (RuntimeException subclasses: NullPointerException, ArrayIndexOutOfBoundsException): no compile-time enforcement." },
  { id: "oop98", diff: "medium", topic: "Exception", q: "What is the difference between 'throw' and 'throws'?", opts: ["No difference", "'throw' actually throws an exception object; 'throws' declares that a method might throw exceptions", "'throws' throws; 'throw' declares", "Both are the same keyword"], ans: 1, exp: "'throw' is used inside a method body to actually throw an exception: throw new IOException(). 'throws' is in the method signature to declare which checked exceptions a method can throw." },
  { id: "oop99", diff: "medium", topic: "Exception", q: "Can we have a try block without a catch block?", opts: ["No, always need catch", "Yes, with a finally block", "Yes, always", "No, try needs both catch and finally"], ans: 1, exp: "try-finally is valid without catch. Also try-with-resources doesn't need explicit catch. You need at least one of: catch block, finally block, or both." },
  { id: "oop100", diff: "medium", topic: "Exception", q: "What does the finally block guarantee?", opts: ["It runs only on exception", "It runs only on normal execution", "It always runs regardless of whether an exception occurred or was caught (except System.exit())", "It runs before try"], ans: 2, exp: "finally always executes (even if return is hit in try/catch), making it ideal for cleanup (closing streams, DB connections). Only System.exit() or JVM crash can skip finally." },
  { id: "oop101", diff: "medium", topic: "Collections", q: "What is the difference between ArrayList and LinkedList?", opts: ["No difference", "ArrayList uses array (fast random access, slow insert/delete in middle); LinkedList uses doubly linked list (fast insert/delete, slow random access)", "LinkedList uses array; ArrayList uses linked list", "ArrayList is thread-safe; LinkedList is not"], ans: 1, exp: "ArrayList: O(1) get, O(n) add/remove in middle (shifting). LinkedList: O(n) get (traversal), O(1) add/remove at head/tail. Use ArrayList for read-heavy; LinkedList for frequent insertions at ends." },
  { id: "oop102", diff: "medium", topic: "Collections", q: "What is the difference between HashMap and Hashtable?", opts: ["No difference", "HashMap: not synchronized, allows one null key; Hashtable: synchronized, no null keys/values, legacy", "Hashtable is faster", "HashMap is sorted"], ans: 1, exp: "HashMap: not thread-safe, allows one null key and multiple null values, faster. Hashtable: thread-safe (synchronized), no nulls, legacy. Prefer ConcurrentHashMap over Hashtable for thread safety with better performance." },
  { id: "oop103", diff: "medium", topic: "Collections", q: "What is the difference between HashSet and TreeSet?", opts: ["No difference", "HashSet: unordered, O(1) operations; TreeSet: sorted (natural/Comparator order), O(log n) operations, implements NavigableSet", "TreeSet is faster", "HashSet is sorted"], ans: 1, exp: "HashSet uses HashMap internally â€” no order guarantee, O(1) average. TreeSet uses Red-Black tree â€” maintains sorted order, O(log n). Use TreeSet when you need sorted iteration." },
  { id: "oop104", diff: "medium", topic: "Basics", q: "What is the Comparable interface?", opts: ["For comparing objects with ==", "A functional interface with compareTo() that defines the natural ordering of a class's instances", "An interface for sorting arrays only", "For comparing class types"], ans: 1, exp: "Comparable<T> has compareTo(T o): returns negative (this < o), 0 (equal), positive (this > o). Defines the natural ordering. Used by Collections.sort() and TreeSet without a separate Comparator." },
  { id: "oop105", diff: "medium", topic: "Basics", q: "What is the Comparator interface?", opts: ["Same as Comparable", "A functional interface that defines external/custom ordering logic, separate from the class being compared", "An interface for natural ordering", "Used only with arrays"], ans: 1, exp: "Comparator<T> has compare(T o1, T o2). Provides external/alternative ordering without modifying the class. Multiple Comparators can exist for the same class (by name, by age, etc.). Used in Collections.sort(list, comparator)." },
  { id: "oop106", diff: "medium", topic: "Basics", q: "What is a lambda expression?", opts: ["A new class type", "A concise, anonymous function syntax (()->), primarily used to implement functional interfaces", "A static method reference", "A recursive method"], ans: 1, exp: "Lambdas: (params) -> expression or (params) -> {body}. They implement functional interfaces inline. e.g., list.sort((a,b) -> a.compareTo(b)). They close over effectively-final variables." },
  { id: "oop107", diff: "medium", topic: "Basics", q: "What is a Stream in Java (java.util.stream)?", opts: ["An I/O byte stream", "A pipeline of operations on a data source (collections, arrays) for functional-style processing", "A thread pool", "A database connection"], ans: 1, exp: "Java 8 Streams support declarative, functional-style data processing: filter, map, reduce, collect. Streams are lazy (processed only when terminal operation is called) and can be parallel." },
  { id: "oop108", diff: "medium", topic: "Basics", q: "What is the difference between intermediate and terminal operations in Streams?", opts: ["No difference", "Intermediate operations (filter, map) return a Stream and are lazy; terminal operations (collect, forEach, count) trigger processing and return a result", "Terminal operations return a Stream", "Intermediate operations are eager"], ans: 1, exp: "Intermediate: lazy, return Stream, chained (filter(), map(), sorted()). Terminal: trigger the pipeline, return a result or side effect (collect(), forEach(), reduce(), count(), findFirst())." },
  { id: "oop109", diff: "medium", topic: "Design", q: "What is the Decorator pattern?", opts: ["Adding methods to a subclass", "Wrapping an object to add behaviour dynamically without subclassing", "Creating objects via factory", "Hiding object creation"], ans: 1, exp: "Decorator: wraps an object with another object implementing the same interface, adding functionality. Java I/O streams are the classic example: new BufferedReader(new FileReader('file'))." },
  { id: "oop110", diff: "medium", topic: "Design", q: "What is the Strategy pattern?", opts: ["A pattern for creating objects", "Defining a family of algorithms, encapsulating each, and making them interchangeable at runtime", "A pattern for organizing inheritance", "Observer notification pattern"], ans: 1, exp: "Strategy: encapsulate interchangeable behaviours (algorithms) behind a common interface. The context delegates to the strategy at runtime. e.g., different sorting algorithms, payment methods, compression algorithms." },
  { id: "oop111", diff: "medium", topic: "Inheritance", q: "What is the Liskov Substitution Principle (LSP)?", opts: ["A subclass can replace its superclass without altering correctness of the program", "A class must implement all interfaces", "Favour composition over inheritance", "Program to interfaces, not implementations"], ans: 0, exp: "LSP (L in SOLID): objects of a superclass must be replaceable with objects of any subclass without breaking the program. If class B extends A, anywhere A is used, B should work correctly without the caller knowing." },
  { id: "oop112", diff: "medium", topic: "Design", q: "What does SOLID stand for?", opts: ["5 Java keywords", "Single Responsibility, Open/Closed, Liskov Substitution, Interface Segregation, Dependency Inversion", "5 OOP pillars", "Standard Object Language Interface Design"], ans: 1, exp: "SOLID: 5 principles of OOP design. S=Single Responsibility. O=Open for extension/Closed for modification. L=Liskov Substitution. I=Interface Segregation. D=Dependency Inversion." },
  { id: "oop113", diff: "medium", topic: "Design", q: "What is Dependency Injection (DI)?", opts: ["Injecting code at runtime", "Providing dependencies (objects a class needs) from outside rather than the class creating them â€” enables loose coupling and testability", "A design pattern for interfaces", "Creating objects dynamically"], ans: 1, exp: "DI: instead of class A creating class B internally (new B()), B is provided to A externally (via constructor, setter, or field injection). Used in Spring, testing with mocks. Implements Dependency Inversion Principle." },
  { id: "oop114", diff: "medium", topic: "Basics", q: "What is the purpose of the 'instanceof' pattern matching (Java 16+)?", opts: ["Checks if null", "Pattern matching: instanceof checks type AND extracts a typed variable in one expression, eliminating explicit cast", "Creates new instances", "Checks method signatures"], ans: 1, exp: "Java 16+: if (obj instanceof String s) { s.length(); } â€” checks type and binds the variable 's' of type String in scope. Eliminates the boilerplate cast after instanceof." },
  { id: "oop115", diff: "medium", topic: "Basics", q: "What is a record class (Java 16+)?", opts: ["A legacy class type", "A compact, immutable data carrier class with auto-generated constructor, getters, equals, hashCode, toString", "A mutable POJO class", "An abstract data type"], ans: 1, exp: "record Person(String name, int age) {} auto-generates: constructor, accessors (name(), age()), equals(), hashCode(), toString(). Designed for immutable data transfer objects (DTOs). Fields are final by default." },
  { id: "oop116", diff: "medium", topic: "Basics", q: "What is a sealed class (Java 17+)?", opts: ["A final class", "A class that restricts which classes can extend it using 'permits' clause", "A class with no constructor", "A private class"], ans: 1, exp: "sealed class Shape permits Circle, Rectangle {} â€” only Circle and Rectangle can extend Shape. Enables exhaustive pattern matching on a fixed type hierarchy." },
  { id: "oop117", diff: "medium", topic: "Basics", q: "What is object serialization?", opts: ["Converting object to String", "Converting an object's state to a byte stream for storage or transmission", "Sorting objects", "Compressing objects"], ans: 1, exp: "Serialization (implementing Serializable): converts object state to a byte stream. Deserialization reconstructs the object. Used in file storage, network transmission, RMI." },
  { id: "oop118", diff: "medium", topic: "Design", q: "What is the Template Method pattern?", opts: ["Creating object templates", "Defining the skeleton of an algorithm in a superclass, deferring some steps to subclasses", "Creating interface templates", "Builder pattern variant"], ans: 1, exp: "Template Method: an abstract class defines the algorithm's skeleton in a final method, calling abstract hook methods. Subclasses override hooks to customise steps without changing the overall algorithm structure." },
  { id: "oop119", diff: "medium", topic: "Basics", q: "What is an enum in Java OOP terms?", opts: ["A primitive type", "A special class representing a fixed set of constants, with type safety and ability to have fields and methods", "An interface type", "A generic type"], ans: 1, exp: "Java enums are full classes: they can have fields, methods, constructors, and implement interfaces. Each constant (NORTH, SOUTH) is a static final instance of the enum class." },
  { id: "oop120", diff: "medium", topic: "Basics", q: "What is the purpose of the @Override annotation?", opts: ["Creates a new method", "Signals the compiler to verify that the method actually overrides a superclass method â€” catches typos/signature mismatches at compile time", "Makes a method final", "Makes a method abstract"], ans: 1, exp: "@Override is checked at compile time. If the annotated method doesn't override (due to typo, wrong signature), the compiler gives an error. Best practice to always annotate overriding methods." },
  { id: "oop121", diff: "medium", topic: "Collections", q: "What is the difference between fail-fast and fail-safe iterators?", opts: ["No difference", "Fail-fast throws ConcurrentModificationException if the collection is modified during iteration; fail-safe iterates over a copy and doesn't throw", "Fail-safe is for arrays only", "Fail-fast uses snapshots"], ans: 1, exp: "Fail-fast (ArrayList, HashMap iterators): detect structural modification via modCount, throw ConcurrentModificationException. Fail-safe (CopyOnWriteArrayList, ConcurrentHashMap): work on a snapshot/copy, no exception." },
  { id: "oop122", diff: "medium", topic: "Basics", q: "What is inner class? How does it differ from a static nested class?", opts: ["No difference", "Inner class is non-static and has access to enclosing instance; static nested class has no implicit outer instance reference", "Static nested class is inner; inner class is outer", "Inner classes are only anonymous"], ans: 1, exp: "Inner class: needs an outer instance to be created, can access outer class members. Static nested class: no outer instance needed, can only access outer class's static members." },
  { id: "oop123", diff: "medium", topic: "Basics", q: "What is an anonymous inner class?", opts: ["A class with no fields", "A one-time-use class defined and instantiated in a single expression, implementing an interface or extending a class", "A class in another package", "A lambda expression"], ans: 1, exp: "Anonymous inner class: new Comparator<String>() { public int compare(String a, String b) { return a.compareTo(b); } }. Defined and instantiated at once. Often replaced by lambdas in Java 8+." },
  { id: "oop124", diff: "medium", topic: "Design", q: "What is the Adapter pattern?", opts: ["Adapting a class to a new OOP language", "Converting the interface of a class into another interface clients expect â€” bridges incompatible interfaces", "Adapting to a new database", "A parallel programming pattern"], ans: 1, exp: "Adapter: wraps an existing class with a new interface. Like a power plug adapter â€” the existing Adaptee class has the functionality but wrong interface; Adapter makes it compatible." },
  { id: "oop125", diff: "medium", topic: "Basics", q: "What is the 'var' keyword (Java 10+)?", opts: ["Declares a variable with no type", "Local variable type inference â€” compiler infers the type from the right-hand side", "Makes a variable variable (mutable)", "Declares a volatile variable"], ans: 1, exp: "var x = new ArrayList<String>() â€” the compiler infers x is ArrayList<String>. Only for local variables. The type is still statically known at compile time â€” var is NOT dynamic typing." },
  { id: "oop126", diff: "medium", topic: "Basics", q: "What are Optional<T> and why are they used?", opts: ["A type that can hold any type", "A container that may or may not contain a non-null value â€” used to avoid NullPointerException and make optional return values explicit", "A generic collection", "A thread-safe wrapper"], ans: 1, exp: "Optional<T>: either contains a value (isPresent()=true) or is empty. Forces callers to handle the null case explicitly: optional.orElse('default'), optional.ifPresent(val->...). Expressive alternative to returning null." },
  { id: "oop127", diff: "medium", topic: "Design", q: "What is the Proxy pattern?", opts: ["Hiding implementation", "Providing a surrogate or placeholder for another object to control access, add lazy initialisation, logging, or remote access", "Creating multiple objects", "Sorting objects by proxy"], ans: 1, exp: "Proxy: same interface as the real object, delegating calls while adding: access control, lazy initialisation, caching, logging, or remote access. Java's java.lang.reflect.Proxy provides dynamic proxies at runtime." },
  { id: "oop128", diff: "medium", topic: "Basics", q: "What is method reference in Java 8+?", opts: ["A pointer to a method's memory address", "A shorthand notation for a lambda that simply calls an existing method: ClassName::methodName", "A reference to a constructor", "Referencing methods from other classes only"], ans: 1, exp: "Method references: shorthand for lambdas. Types: (1) Static: Math::abs, (2) Instance of specific type: String::length, (3) Instance of particular object: myObj::method, (4) Constructor: ArrayList::new." },
  { id: "oop129", diff: "medium", topic: "Generics", q: "What is the difference between <? extends T> and <? super T>?", opts: ["No difference", "<? extends T> is upper-bounded (for reading/producers); <? super T> is lower-bounded (for writing/consumers) â€” PECS principle", "<? super T> is for reading", "Both are upper-bounded"], ans: 1, exp: "PECS (Producer Extends, Consumer Super): use <? extends T> to READ from a structure (producer), <? super T> to WRITE to it (consumer). Collections.copy(List<? super T> dest, List<? extends T> src) demonstrates this." },
  { id: "oop130", diff: "medium", topic: "Basics", q: "What is the difference between composition and aggregation?", opts: ["No difference", "Composition: strong ownership â€” child cannot exist without parent (lifecycle tied). Aggregation: weak relationship â€” child can exist independently", "Aggregation is stronger", "Composition is weaker"], ans: 1, exp: "Composition: House HAS-A Room â€” the Room's lifecycle is tied to the House (destroyed with it). Aggregation: University HAS-AN Professor â€” the Professor exists independently." },
  { id: "oop131", diff: "medium", topic: "Design", q: "What is the Facade pattern?", opts: ["Same as Adapter", "Provides a simplified unified interface to a complex subsystem â€” clients interact with the facade rather than the complex internals", "A pattern for managing dependencies", "Hiding abstract classes from clients"], ans: 1, exp: "Facade: HomeTheater.watchMovie() internally calls: amplifier.on(), dvdPlayer.load(), projector.widescreen(), lights.dim(). Clients call one method instead of coordinating many. Doesn't prevent access to subsystem â€” just simplifies the common case." },
  { id: "oop132", diff: "medium", topic: "Design", q: "What is the Composite pattern?", opts: ["Combining two classes", "Treating individual objects and compositions of objects uniformly â€” tree structures where leaf and composite implement the same interface", "Database composition", "Thread composition"], ans: 1, exp: "Composite: Component interface implemented by Leaf (no children) and Composite (has children, delegates operations). Used in file systems (File/Folder), GUI (Widget/Panel), org charts. Client code treats both leaves and composites identically." },
  { id: "oop133", diff: "medium", topic: "Basics", q: "What is the difference between association, aggregation, and composition?", opts: ["They are the same", "Association: general 'uses' relationship. Aggregation: HAS-A with independent lifecycle. Composition: HAS-A with dependent lifecycle (child dies with parent)", "Composition is weakest", "Aggregation implies inheritance"], ans: 1, exp: "Association: Teacher teaches Student (no ownership). Aggregation: Team HAS Players (Players exist independently). Composition: Human HAS-A Heart (Heart dies with Human). Increasing strength: association < aggregation < composition." },
  { id: "oop134", diff: "medium", topic: "Generics", q: "What is a raw type in Java and why is it dangerous?", opts: ["A primitive type", "Using a generic class without type parameters â€” bypasses compile-time type checking and can cause ClassCastException at runtime", "A type for raw data", "An unboxed wrapper type"], ans: 1, exp: "Raw type: List list = new ArrayList() (no <T>). Compiler allows inserting any type. At runtime, when you get and cast an element, ClassCastException can occur. Raw types exist for backward compatibility â€” avoid them in new code." },
  { id: "oop135", diff: "medium", topic: "Design", q: "What is the Command pattern?", opts: ["Commanding other objects", "Encapsulating a request as an object â€” enables parameterising requests, queuing, logging, and undo/redo operations", "A singleton variant", "Threading pattern"], ans: 1, exp: "Command: encapsulate a request as an object with execute()/undo() methods. Enables: queuing requests, logging, undo/redo stacks, transactional behaviour. GUI actions, database transactions, and job schedulers use this." },
  { id: "oop136", diff: "medium", topic: "Design", q: "What is the Chain of Responsibility pattern?", opts: ["Calling methods in a chain", "Passing a request along a chain of handlers â€” each handler decides to process or pass to the next", "Inheritance chain", "Observer notification chain"], ans: 1, exp: "CoR: decouple sender from receiver. Request travels through a chain of handlers; each either handles it or passes it on. Used in event handling (Java AWT/Swing), HTTP filters (Servlet Filter chain), logging frameworks." },
  { id: "oop137", diff: "medium", topic: "Design", q: "What is the Memento pattern?", opts: ["Memory management", "Capturing and externalising an object's internal state to restore it later â€” without violating encapsulation", "Caching pattern", "State machine pattern"], ans: 1, exp: "Memento: Originator creates a Memento (snapshot of state), stored by Caretaker. Originator can restore from Memento. Enables undo/redo without exposing internals." },
  { id: "oop138", diff: "medium", topic: "SOLID", q: "Explain the Open/Closed Principle.", opts: ["Classes must be open for all changes", "Software entities should be open for extension but closed for modification â€” add new behaviour by adding new code, not changing existing code", "Only use open source", "All methods must be overridable"], ans: 1, exp: "OCP: add functionality by extending (new subclasses, new implementations) rather than modifying existing tested code. Achieved via: interfaces, abstract classes, strategy pattern." },
  { id: "oop139", diff: "medium", topic: "SOLID", q: "Explain the Interface Segregation Principle (ISP).", opts: ["Use large interfaces", "Clients should not be forced to depend on interfaces they don't use â€” split large interfaces into smaller, more specific ones", "Interfaces should have 10+ methods", "All interfaces must be functional"], ans: 1, exp: "ISP: instead of one fat interface with 20 methods, have multiple focused interfaces. Implementing classes only depend on what they actually use." },
  { id: "oop140", diff: "medium", topic: "SOLID", q: "Explain the Dependency Inversion Principle (DIP).", opts: ["High-level modules depend on low-level modules", "High-level modules should not depend on low-level modules â€” both should depend on abstractions (interfaces/abstract classes)", "Avoid interfaces", "Only abstract classes allowed"], ans: 1, exp: "DIP: decouple high-level policy from low-level details. High-level: OrderProcessor. Low-level: EmailService, DatabaseLogger. Both should depend on: INotificationService, ILogger abstractions. Enables swapping implementations." },
  { id: "oop141", diff: "medium", topic: "Basics", q: "What is reflection in Java?", opts: ["Mirroring code", "The ability to inspect and manipulate classes, methods, and fields at runtime â€” even private members", "A design pattern", "Code generation"], ans: 1, exp: "Reflection (java.lang.reflect): inspect Class objects, list methods/fields, invoke methods by name, create instances dynamically. Used in frameworks (Spring, JUnit, Jackson). Trade-offs: loses compile-time safety, slower than direct calls." },
  { id: "oop142", diff: "medium", topic: "Basics", q: "What is dynamic proxy in Java?", opts: ["A cached object", "A proxy object created at runtime using java.lang.reflect.Proxy that implements specified interfaces â€” all method calls are dispatched to an InvocationHandler", "A design pattern", "A serialization technique"], ans: 1, exp: "Dynamic proxy: Proxy.newProxyInstance(loader, interfaces[], handler). The handler's invoke() intercepts all calls. Used in Spring AOP (transaction, security, logging), RPC stubs, mocking frameworks (Mockito)." },
  { id: "oop143", diff: "medium", topic: "Generics", q: "What is heap pollution in Java generics?", opts: ["Memory leak", "A situation where a variable of parameterized type refers to an object that is not of that type â€” caused by raw types or unchecked casts, leading to ClassCastException later", "GC fragmentation", "Stack overflow from generics"], ans: 1, exp: "Heap pollution: List<String> list = (List<String>) rawList; â€” inserts the wrong type silently. The ClassCastException occurs later when you retrieve and use the element, making the bug hard to trace." },
  { id: "oop144", diff: "medium", topic: "Design", q: "What is the difference between inheritance and composition, and why prefer composition?", opts: ["Inheritance is always better", "Inheritance couples subclass to superclass (brittle base class problem); composition is more flexible â€” change behaviour at runtime, no compile-time binding, easier testing", "Composition is always wrong", "They are equivalent"], ans: 1, exp: "'Prefer composition over inheritance' (GoF): inheritance exposes superclass internals (fragile), breaks encapsulation, is static. Composition: flexible (swap implementations at runtime), testable (mock dependencies)." },
  { id: "oop145", diff: "medium", topic: "Basics", q: "What is Inversion of Control (IoC)?", opts: ["Inverting loop control", "A principle where the control of object creation and lifecycle is given to a container/framework rather than the application code", "Reversing inheritance", "Inverting method calls"], ans: 1, exp: "IoC: instead of your code calling the framework, the framework calls your code (Hollywood Principle). Spring IoC container creates and wires beans. Dependency Injection is one implementation of IoC." },
  { id: "oop146", diff: "medium", topic: "Basics", q: "What is a covariant vs contravariant type system?", opts: ["Not relevant to Java", "Covariant: if B extends A, then String[] IS-A Object[] (arrays are covariant). Generics are invariant: List<String> is NOT a subtype of List<Object>. Wildcards provide use-site variance.", "Java is fully covariant", "Java is fully contravariant"], ans: 1, exp: "Java arrays are covariant (String[] IS-A Object[]) â€” can cause ArrayStoreException. Java generics are INVARIANT (List<String> is NOT a subtype of List<Object>). Wildcards provide use-site variance: <? extends T> (covariant), <? super T> (contravariant)." },
  { id: "oop147", diff: "medium", topic: "Basics", q: "What is the difference between early binding and late binding?", opts: ["No difference", "Early/static binding: method resolved at compile time (overloading, static methods). Late/dynamic binding: method resolved at runtime (overriding) based on actual object type", "Late binding is for constructors", "Early binding is for interfaces"], ans: 1, exp: "Early binding: compiler knows exactly which method to call (overloaded methods, static methods, final methods, private methods). Late binding: JVM determines at runtime which method to call via vtable lookup â€” enables polymorphism." },
  { id: "oop148", diff: "medium", topic: "Design", q: "What is the Null Object pattern?", opts: ["Using null safely", "Providing a default object with do-nothing (neutral) behaviour to avoid null checks â€” implements the same interface as real objects", "Creating null pointers safely", "A pattern to detect null"], ans: 1, exp: "Null Object: instead of returning null, return a NullCustomer object that implements Customer with empty/no-op implementations. Eliminates null checks in client code. Optional<T> is a modern approach." },
  { id: "oop149", diff: "medium", topic: "Basics", q: "What is object interning?", opts: ["Converting objects to primitives", "Caching and reusing objects with the same value â€” String.intern(), Integer cache (-128 to 127) are examples", "Serializing objects", "Compressing objects"], ans: 1, exp: "Interning: maintaining a pool of canonical objects. Requesting the same value returns the cached instance. String.intern() adds to pool. Integer.valueOf(127) returns cached Integer. Saves memory." },
  { id: "oop150", diff: "medium", topic: "Design", q: "What is the Iterator pattern and how does Java implement it?", opts: ["Iterating over arrays only", "Providing a way to sequentially access elements of a collection without exposing its underlying representation â€” Java: Iterable<T> + Iterator<T> interfaces", "A sorting algorithm", "A design pattern for arrays"], ans: 1, exp: "Iterator: Collection implements Iterable<T> (has iterator()). Iterator<T> has hasNext(), next(), remove(). for-each loop uses Iterable. The pattern decouples traversal from the collection." },
  { id: "oop151", diff: "medium", topic: "Design", q: "What is the State pattern?", opts: ["Managing static fields", "Allowing an object to alter its behaviour when its internal state changes â€” the object will appear to change its class", "Thread state management", "Exception state management"], ans: 1, exp: "State: object behaviour changes with state. Instead of large if/switch on state, each state is a class implementing a State interface. Context delegates to current state object. Used in vending machines, traffic lights, order processing." },
  { id: "oop152", diff: "medium", topic: "Design", q: "What is the Visitor pattern?", opts: ["Visiting design websites", "Separating an algorithm from the object structure it operates on â€” add new operations without modifying the classes", "Object traversal pattern", "Database visitor pattern"], ans: 1, exp: "Visitor: add operations to object structures without modifying them. Element has accept(Visitor), Visitor has visit(ConcreteElement). Double dispatch: the right visit() is chosen based on both element type and visitor type. Used in compilers (AST traversal)." },
  { id: "oop153", diff: "medium", topic: "Basics", q: "What is the difference between deep copy and clone() in Java?", opts: ["No difference", "clone() by default is a shallow copy (Object.clone()). Deep copy requires manually copying all referenced objects or using serialization/copy constructors", "clone() is always deep", "Deep copy is impossible in Java"], ans: 1, exp: "Object.clone() copies field values (shallow). For a deep copy: (1) Implement custom clone() that clones nested objects, (2) Use copy constructor, (3) Serialise and deserialise." },
  { id: "oop154", diff: "medium", topic: "Basics", q: "What is the 'Fragile Base Class' problem in OOP?", opts: ["Base classes with few methods", "When a change to a base class breaks subclasses, even though the subclasses didn't change â€” caused by inheritance coupling", "Null pointer from base classes", "Final class issues"], ans: 1, exp: "Fragile base class: adding/modifying a method in a base class can unexpectedly break subclasses that override related methods. This is why 'prefer composition over inheritance' is good advice." },
  { id: "oop155", diff: "medium", topic: "Design", q: "What is the difference between the Facade and Adapter patterns?", opts: ["No difference", "Facade: simplifies a complex subsystem with a higher-level interface. Adapter: converts one interface to another expected interface. Facade hides complexity; Adapter bridges incompatibility", "Adapter simplifies; Facade converts", "Both hide implementations"], ans: 1, exp: "Facade: creates a simple interface over a complex system. e.g., HomeTheaterFacade.watchMovie() calls TV.on(), DVD.play(). Adapter: converts existing interface to what client expects â€” wraps an incompatible object." },
  { id: "oop156", diff: "hard", topic: "JVM Internals", q: "How does Java implement runtime polymorphism at the JVM level?", opts: ["Via static binding at compile time", "Via a vtable (virtual method table) â€” each object has a pointer to its class's vtable, and virtual method calls are dispatched through this table at runtime", "Via reflection only", "Via bytecode rewriting"], ans: 1, exp: "JVM uses a vtable (virtual dispatch table): each class has a table of method pointers. When you call a virtual method, the JVM looks up the actual object's vtable and calls the correct implementation â€” O(1) dispatch." },
  { id: "oop157", diff: "hard", topic: "Design", q: "What is the difference between the Abstract Factory and Factory Method patterns?", opts: ["No difference", "Factory Method creates one product type via subclass override; Abstract Factory creates families of related products via an interface with multiple factory methods", "Abstract Factory is simpler", "Factory Method creates multiple products"], ans: 1, exp: "Factory Method: one method, one product type, subclasses override it. Abstract Factory: an interface for creating FAMILIES of related products (Button, TextField, Scrollbar) â€” different factories for different platforms produce compatible families." },
  { id: "oop158", diff: "hard", topic: "Design", q: "What is the Flyweight pattern and when is it useful?", opts: ["A pattern for lightweight threads", "A pattern that shares fine-grained objects to reduce memory â€” intrinsic state is shared; extrinsic state is passed", "A pattern for singleton creation", "A pattern for lazy loading"], ans: 1, exp: "Flyweight: share objects to support many similar objects efficiently. Java String pool and Integer.valueOf() (-128 to 127 cache) are examples. Intrinsic state (shared) vs extrinsic state (context-specific, passed in)." },
  { id: "oop159", diff: "hard", topic: "Basics", q: "Explain the double-checked locking Singleton pattern. What problem does 'volatile' solve here?", opts: ["Volatile is not needed", "Without volatile, due to CPU instruction reordering, a partially constructed object could be seen by another thread before the field is fully initialised", "Volatile prevents GC", "Volatile makes the constructor thread-safe"], ans: 1, exp: "Double-checked: if(instance==null){synchronized{if(instance==null){instance=new S()}}}. Without volatile, CPU can reorder: allocate memory â†’ assign reference â†’ initialise. Another thread sees non-null but uninitialised object. volatile prevents reordering." },
  { id: "oop160", diff: "hard", topic: "Generics", q: "Why can't you create generic arrays in Java? e.g., new T[]", opts: ["Syntax limitation", "Type erasure: at runtime, T is erased to Object. An array of T[] would actually be Object[], but arrays are covariant and reifiable â€” this creates heap pollution and type unsafety", "Memory limitation", "JVM limitation"], ans: 1, exp: "Arrays are covariant (String[] IS-A Object[]) and reifiable (type info kept at runtime). Generics are invariant and erased. If T[] were allowed, you could insert the wrong type at runtime â€” heap pollution. Use List<T> instead." },
  { id: "oop161", diff: "hard", topic: "JVM Internals", q: "What is the difference between stack memory and heap memory in Java OOP context?", opts: ["No difference", "Stack: per-thread, stores local variables and method call frames (fast). Heap: shared, stores all objects created with 'new' (slower, GC-managed)", "Heap is per-thread", "Stack stores objects"], ans: 1, exp: "Stack: LIFO, each thread has its own, stores method call frames, local variables, and primitive values. Fast allocation/deallocation. Heap: shared among threads, stores all objects (new). GC manages it." },
  { id: "oop162", diff: "hard", topic: "Design", q: "What is the Interpreter pattern?", opts: ["Code interpretation at runtime", "Defining a representation for a grammar and an interpreter that uses that representation to interpret sentences â€” used for simple languages/rules engines", "A compiler design pattern", "A JVM pattern"], ans: 1, exp: "Interpreter: each grammar rule is a class. Abstract expression has interpret() method. Used for: scripting languages, regular expressions, SQL parsing, rule engines." },
  { id: "oop163", diff: "hard", topic: "Basics", q: "What is the difference between association, aggregation, and composition?", opts: ["They are the same", "Association: general 'uses' relationship. Aggregation: HAS-A with independent lifecycle. Composition: HAS-A with dependent lifecycle (child dies with parent)", "Composition is weakest", "Aggregation implies inheritance"], ans: 1, exp: "Association: Teacher teaches Student (no ownership). Aggregation: Team HAS Players (Players exist independently). Composition: Human HAS-A Heart (Heart dies with Human). Increasing strength: association < aggregation < composition." },
  { id: "oop164", diff: "hard", topic: "JVM Internals", q: "What is the difference between static dispatch and dynamic dispatch in Java?", opts: ["No difference", "Static dispatch: method resolved at compile time (overloading, static methods). Dynamic dispatch: method resolved at runtime using vtable (overriding, virtual methods)", "Dynamic dispatch is slower only", "Static dispatch is for interfaces"], ans: 1, exp: "Static dispatch: overloaded method is chosen by the compiler based on declared type and parameter signature. Dynamic dispatch: overridden method is chosen by JVM at runtime based on actual object type." },
  { id: "oop165", diff: "hard", topic: "Basics", q: "What is a mixin in OOP and how can Java simulate it?", opts: ["A compilation phase", "A way to add multiple behaviours to a class without inheritance â€” Java simulates via interfaces with default methods (Java 8+)", "A type of constructor", "A generic type"], ans: 1, exp: "Mixin: add a set of methods to a class without inheritance. Java 8 default methods enable this: interface Flyable { default void fly() {...} } â€” a class can mix in multiple behaviours by implementing multiple interfaces with default methods." },
  { id: "oop166", diff: "hard", topic: "Basics", q: "What is type coercion vs type casting in Java?", opts: ["They are the same", "Type coercion: automatic implicit conversion (int to double). Type casting: explicit conversion (double to int with possible data loss)", "Casting is implicit", "Coercion requires explicit syntax"], ans: 1, exp: "Widening coercion: int â†’ long â†’ float â†’ double (automatic, no data loss). Narrowing casting: (int) 3.14 â†’ 3 (explicit, may lose data). Object casting: (String) obj â€” explicit, can throw ClassCastException if wrong type." },
  { id: "oop167", diff: "hard", topic: "Basics", q: "What is the difference between deep copy and clone() in Java?", opts: ["No difference", "clone() by default is a shallow copy (Object.clone()). Deep copy requires manually copying all referenced objects or using serialization/copy constructors", "clone() is always deep", "Deep copy is impossible in Java"], ans: 1, exp: "Object.clone() copies field values (shallow). For a deep copy: (1) Implement custom clone() that clones nested objects, (2) Use copy constructor, (3) Serialise and deserialise." },
  { id: "oop168", diff: "hard", topic: "Design", q: "What is the difference between the Proxy and Decorator patterns?", opts: ["No difference", "Proxy controls access to an object (may add lazy init, security, logging). Decorator adds behaviour to an object dynamically. Both use the same interface but differ in intent and how they are composed", "Decorator controls access; Proxy adds behaviour", "They are the same structural pattern"], ans: 1, exp: "Proxy: focuses on controlling access to the real object â€” often the proxy creates the real object lazily or controls who can use it. Decorator: focuses on adding functionality â€” stacked at runtime. Both implement the same interface and delegate, but their PURPOSE differs." },
  { id: "oop169", diff: "hard", topic: "Basics", q: "What is the 'Fragile Base Class' problem in OOP?", opts: ["Base classes with few methods", "When a change to a base class breaks subclasses, even though the subclasses didn't change â€” caused by inheritance coupling", "Null pointer from base classes", "Final class issues"], ans: 1, exp: "Fragile base class: adding/modifying a method in a base class can unexpectedly break subclasses that override related methods. The subclass assumes certain behaviour that changes. This is why 'prefer composition over inheritance' and 'design for inheritance or prohibit it (final)'." },
  { id: "oop170", diff: "hard", topic: "Basics", q: "What is reflection in Java and what are its trade-offs?", opts: ["Mirroring code", "The ability to inspect and manipulate classes, methods, and fields at runtime â€” even private members. Trade-offs: loses compile-time safety, slower, breaks encapsulation", "Only for debugging", "No trade-offs"], ans: 1, exp: "Reflection (java.lang.reflect): inspect Class objects, list methods/fields, invoke methods by name, create instances dynamically. Powers: Spring, JUnit, Jackson. Trade-offs: ~20-50x slower than direct calls, no compile-time safety, breaks encapsulation, security manager restrictions." },
  { id: "oop171", diff: "scenario", topic: "Design Problem", q: "You're building a payment system that needs to support credit card, PayPal, and cryptocurrency payments, with new payment methods added frequently. Which OOP design would you use?", opts: ["One large PaymentProcessor class with if/else for each type", "Strategy pattern: PaymentStrategy interface with CreditCardPayment, PayPalPayment, CryptoPayment implementations â€” swap at runtime without modifying existing code", "Singleton payment class", "Abstract class with switch statement"], ans: 1, exp: "Strategy pattern: each payment method implements PaymentStrategy.pay(). PaymentProcessor holds a reference and delegates. Adding a new method = new class, no existing code change (Open/Closed Principle). Clean, testable, extensible." },
  { id: "oop172", diff: "scenario", topic: "Debug", q: "Your HashMap is losing entries â€” you add an object as a key, modify the object's state, and can no longer find it with get(). What went wrong?", opts: ["HashMap bug", "The object's hashCode() changed after modification, placing it in a different bucket â€” HashMap lookup fails", "The object was garbage collected", "get() has a bug"], ans: 1, exp: "HashMap uses hashCode() to find the bucket. If you modify a key object after insertion (changing fields used in hashCode()), its hash changes. The entry is in the old bucket, but lookup computes a new bucket â€” entry appears lost. Always use immutable keys in HashMap." },
  { id: "oop173", diff: "scenario", topic: "Debug", q: "A Singleton class works fine in single-threaded tests but creates multiple instances in production. What's likely wrong?", opts: ["The Singleton pattern is broken", "The getInstance() check is not synchronized â€” two threads can simultaneously see instance==null and each create an object", "Garbage collector destroys instances", "The constructor is public"], ans: 1, exp: "Race condition: thread A and B both check instance==null (true), both enter the if block, both create instances. Fix: (1) synchronized getInstance(), (2) Double-checked locking with volatile, (3) Initialization-on-demand holder (best: JVM guarantees class loading is thread-safe)." },
  { id: "oop174", diff: "scenario", topic: "Design Problem", q: "You need to log method calls in a large existing codebase of 50+ classes without modifying any existing class. What's the best approach?", opts: ["Manually add logging to every method", "Use dynamic proxies or AOP (Aspect-Oriented Programming) â€” intercept method calls via proxy/aspect without touching original code", "Extend all classes", "Create a Logger subclass for each"], ans: 1, exp: "AOP/Proxy: create a logging handler that intercepts all method calls via java.lang.reflect.Proxy or a framework like AspectJ/Spring AOP. The @Before advice adds logging without modifying existing classes â€” perfect application of the Open/Closed Principle." },
  { id: "oop175", diff: "scenario", topic: "Design Problem", q: "You're designing a document editor with multiple output formats (PDF, HTML, XML). New formats will be added. Objects in the document have complex structures. Which pattern fits best?", opts: ["Factory Method", "Visitor pattern: document elements accept a visitor; each visitor (PdfExportVisitor, HtmlExportVisitor) implements the export â€” add new formats without modifying elements", "Singleton", "Command pattern"], ans: 1, exp: "Visitor: document elements (Paragraph, Image, Table) implement accept(Visitor v). Adding PDF export = new PdfVisitor class only. No modification to existing element classes. Double-dispatch ensures the right visit() method is called per element type." },
  { id: "oop176", diff: "scenario", topic: "Debug", q: "You override equals() in your class but forget to override hashCode(). Your object is added to a HashSet â€” when you check contains() with an equal object, it returns false. Explain.", opts: ["HashSet has a bug", "equals() and hashCode() contract violation: equal objects must have equal hash codes. The HashSet puts the object in one bucket (using default hashCode), but looks for it in a different bucket â€” never finds it", "The object was removed", "equals() override failed"], ans: 1, exp: "HashSet first computes hashCode() to find the bucket, then uses equals() to confirm. With default hashCode() (memory address), two logically equal objects hash to different buckets. The contract breach: equals()=true but hashCode() different means the HashSet can't find the object. Always override both together." },
  { id: "oop177", diff: "scenario", topic: "Design Problem", q: "You need an object that represents 'no customer' (default behaviour) to avoid null checks scattered throughout the codebase. What pattern applies?", opts: ["Singleton pattern", "Null Object pattern: create a NullCustomer that implements Customer with do-nothing/default methods", "Factory pattern", "Abstract class solution"], ans: 1, exp: "Null Object pattern: instead of if(customer != null) { customer.getDiscount(); } everywhere, a NullCustomer.getDiscount() returns 0. Client code doesn't need null checks. Cleaner code, no NullPointerExceptions, same interface as real customers." },
  { id: "oop178", diff: "scenario", topic: "Debug", q: "Your class hierarchy is becoming unmanageable â€” every new feature requires changes in the base class that break subclasses. What refactoring would you apply?", opts: ["Add more subclasses", "Replace inheritance with composition (strategy/delegation) â€” extract behaviours into interfaces, inject them, swap at runtime without fragile base class coupling", "Make the base class final", "Add more abstract methods"], ans: 1, exp: "Fragile base class problem. Solution: favour composition. Extract FlyBehaviour, QuackBehaviour interfaces. Duck has a FlyBehaviour (not IS-A). New behaviour = new class. No change to existing classes. This is the Head First Design Patterns 'Duck example' â€” classic composition over inheritance." },
  { id: "oop179", diff: "scenario", topic: "Design Problem", q: "You're building a notification system that sends alerts via email, SMS, and push notifications, and combinations of these. How do you design it to avoid class explosion?", opts: ["Create EmailSMSNotifier, EmailPushNotifier, SMSPushNotifier, EmailSMSPushNotifier classes", "Decorator pattern: wrap notifications around each other â€” new PushDecorator(new SMSDecorator(new EmailNotifier())) â€” combine behaviours at runtime", "Inheritance with all combinations", "Singleton notifier"], ans: 1, exp: "Decorator pattern: without it, you'd need 7 classes for all combinations of 3 notification types (class explosion). With decorator: each type is a decorator that wraps another Notifier. Combine freely at runtime. Adding a 4th type = one new class, not 8 more." },
  { id: "oop180", diff: "scenario", topic: "Design Problem", q: "You need to support undo/redo in a text editor. Which pattern would you implement?", opts: ["Observer pattern", "Command pattern with a history stack: each operation is a Command object with execute() and undo(). Maintain an undo stack and redo stack", "Strategy pattern", "Factory pattern"], ans: 1, exp: "Command pattern: TextCommand(InsertCommand, DeleteCommand) with execute()/undo(). Maintain undoStack and redoStack. Ctrl+Z: undoStack.pop().undo(), push to redoStack. Ctrl+Y: redoStack.pop().execute(), push to undoStack." },
  { id: "oop181", diff: "scenario", topic: "Debug", q: "You call a method on a subclass through a superclass reference and get unexpected behaviour. The parent method is calling a method that's been overridden in the child. What Java mechanism causes this?", opts: ["Bug in Java", "Dynamic dispatch / virtual method invocation: even when called from within the superclass constructor or method, the overridden version in the subclass is invoked â€” can cause issues in constructors", "Reflection issue", "Compile-time binding"], ans: 1, exp: "Dynamic dispatch: calls to overridden methods always dispatch to the most-derived implementation, even from within superclass code. Dangerous in constructors: if superclass constructor calls an overrideable method, the subclass override runs BEFORE the subclass constructor completes, accessing uninitialised fields." },
  { id: "oop182", diff: "scenario", topic: "Design Problem", q: "Your application needs to connect to different databases (MySQL, PostgreSQL, MongoDB) configurable at startup. How do you design database connectivity using OOP?", opts: ["Hardcode each database", "Abstract Factory: DatabaseFactory creates Connection, Statement, ResultSet families for each DB. Factory chosen at startup based on config. Client code works against interfaces only", "Singleton connection", "if/else for each database"], ans: 1, exp: "Abstract Factory: MySQLFactory, PostgresFactory, MongoFactory each implement DatabaseFactory creating compatible Connection, QueryBuilder, ResultParser families. Swap factory at startup. Client code never sees DB-specific classes â€” pure interface programming." },
  { id: "oop183", diff: "scenario", topic: "Debug", q: "You use a List<Dog> where a List<Animal> is expected and get a compile error, even though Dog extends Animal. Why?", opts: ["Compiler bug", "Java generics are invariant â€” List<Dog> is NOT a subtype of List<Animal>. If it were, you could add a Cat to a List<Dog> via the List<Animal> reference â€” type safety would break", "Incorrect class hierarchy", "Classloader issue"], ans: 1, exp: "Invariance: even though Dog IS-A Animal, List<Dog> IS-NOT-A List<Animal>. Consider: if allowed, List<Animal> animals = dogList; animals.add(new Cat()); â€” dogList now contains a Cat! Use wildcard: List<? extends Animal> for read-only access to any animal list." },
  { id: "oop184", diff: "scenario", topic: "Design Problem", q: "You're designing a file system with files and directories, where directories can contain other directories and files, and you want to treat files and directories uniformly for operations like size() and print(). Which pattern?", opts: ["Inheritance only", "Composite pattern: FileSystemComponent interface with File (leaf) and Directory (composite containing a List<FileSystemComponent>). size() and print() work uniformly on both", "Observer pattern", "Decorator pattern"], ans: 1, exp: "Composite pattern: Directory.size() = sum of children's size(). File.size() = actual size. Client calls root.size() without caring about the tree structure. Perfectly models part-whole hierarchies like file systems, org charts, GUI component trees." },
  { id: "oop185", diff: "scenario", topic: "Design Problem", q: "A class has 12 constructor parameters, many optional. Objects are hard to create correctly. Which design pattern solves this?", opts: ["Factory Method", "Builder pattern: MyClass obj = new MyClass.Builder().name('A').age(25).email('x').build() â€” fluent, readable, validates at build() call, avoids telescoping constructors", "Singleton pattern", "Abstract Factory"], ans: 1, exp: "Builder pattern: telescoping constructors (overloading for each parameter combination) are unreadable and error-prone. Builder provides a fluent interface, makes optional vs required clear, validates at build(), and creates immutable objects." },
  { id: "oop186", diff: "scenario", topic: "Debug", q: "You implement Cloneable and call super.clone(), but changes to the cloned object still affect the original. What's the problem?", opts: ["clone() doesn't work", "Object.clone() performs a shallow copy â€” reference fields in the clone point to the SAME objects as the original. You must manually deep-clone each mutable reference field", "Cloneable is broken", "The objects are shared by design"], ans: 1, exp: "Shallow clone: primitive fields are copied (independent). Reference fields point to the SAME objects. Modifying a nested list in the clone modifies the original's list too. Deep copy: clone.list = new ArrayList<>(this.list) in your overridden clone() method." },
  { id: "oop187", diff: "scenario", topic: "Design Problem", q: "You need to add caching to an existing database access class without modifying it (it's from a third-party library). Which pattern?", opts: ["Extend the class", "Proxy pattern: create a CachingProxy that implements the same interface, wraps the real DatabaseAccessor, checks cache before delegating to the real object", "Decorator pattern", "Adapter pattern"], ans: 1, exp: "Proxy pattern (caching proxy): wraps the real object with the same interface, checks cache before calling the real method, and stores results. Client code unchanged." },
  { id: "oop188", diff: "scenario", topic: "Debug", q: "You have a class with 20 methods. Some implementing classes only use 3 of these methods but are forced to implement all 20 with empty bodies. What principle is being violated?", opts: ["Single Responsibility", "Interface Segregation Principle (ISP): one fat interface forces clients to depend on methods they don't use. Solution: split into smaller, focused interfaces", "Dependency Inversion", "Liskov Substitution"], ans: 1, exp: "ISP violation: a Printable interface with print(), scan(), fax(), copy() forces a SimplePrinter to implement scan(), fax(), copy() with empty/exception bodies. Split: Printable, Scannable, Faxable. SimplePrinter only implements Printable." },
  { id: "oop189", diff: "scenario", topic: "Design Problem", q: "You're building a GUI framework. You want button click events to trigger multiple independent actions (logging, analytics, UI update) without coupling the button to those actions. Which pattern?", opts: ["Direct method calls in button", "Observer pattern: Button (Subject) notifies all registered ActionListeners (Observers) on click. Add/remove listeners at runtime without modifying Button", "Singleton observer", "Factory pattern"], ans: 1, exp: "Observer: Java's ActionListener, EventListener, and the entire AWT/Swing event system use this. Button.addActionListener(listener) registers observers. On click, notifyAll() fires all listeners independently." },
  { id: "oop190", diff: "scenario", topic: "Debug", q: "You notice that subclassing a third-party class and overriding its methods causes unexpected behaviour after a library update. The base class added a new method that calls your overridden method. What principle applies?", opts: ["Just update your code", "Fragile base class problem + violation of Design for Inheritance or prohibit it. Solution: prefer composition (wrap the third-party class) rather than extending it", "File a bug report", "Use reflection instead"], ans: 1, exp: "When you extend a class, you're tightly coupled to its internals. A base class update can break subclasses unexpectedly. Joshua Bloch's advice: 'Design and document for inheritance, or else prohibit it (make class final).' Wrapping (composition) is safer." },
  { id: "oop191", diff: "scenario", topic: "Design Problem", q: "You need to parse multiple configuration formats (JSON, XML, YAML). The parsing logic is similar â€” read source, validate, map to domain objects. Only the reading step differs. Which pattern?", opts: ["One parser with if/else", "Template Method pattern: abstract ConfigParser with final parseConfig() calling abstract readSource() + concrete validate() + mapToDomain(). Subclasses (JsonParser, XmlParser) only override readSource()", "Strategy pattern", "Factory pattern"], ans: 1, exp: "Template Method: the algorithm skeleton (readâ†’validateâ†’map) is fixed in the base class. Only the varying step (readSource) is abstract. Each format subclass implements just readSource(). Avoids code duplication in the common steps." },
  { id: "oop192", diff: "scenario", topic: "Debug", q: "Your TreeSet<MyClass> is throwing a ClassCastException when adding a second element. What's likely missing from MyClass?", opts: ["A constructor", "MyClass doesn't implement Comparable<MyClass>. TreeSet requires elements to be comparable (uses compareTo() to maintain sorted order). Without it, adding the 2nd element fails when TreeSet tries to compare it", "A toString() method", "A hashCode() method"], ans: 1, exp: "TreeSet (and sorted collections) requires elements to implement Comparable or a Comparator to be provided. Without compareTo(), TreeSet can't determine element order and throws ClassCastException on the 2nd add." },
  { id: "oop193", diff: "scenario", topic: "Design Problem", q: "You need to implement a logging framework where different loggers (ConsoleLogger, FileLogger, EmailLogger) handle messages at different severity levels and can be chained. Which pattern fits?", opts: ["Observer pattern", "Chain of Responsibility: each logger has a next reference and handles messages at or above its level, passing lower-severity messages up the chain", "Strategy pattern", "Command pattern"], ans: 1, exp: "CoR: ConsoleLogger handles DEBUG (passes ERROR up). FileLogger handles WARN (passes ERROR up). EmailLogger handles ERROR. Chain: consoleâ†’fileâ†’email. A DEBUG message is handled by console only. An ERROR message propagates the whole chain." },
  { id: "oop194", diff: "scenario", topic: "Design Problem", q: "You're designing a hotel booking system. Rooms have states (Available, Reserved, CheckedIn, CheckedOut). Behaviour differs significantly by state. Which pattern?", opts: ["Multiple if/else blocks", "State pattern: Room has a RoomState field. Each state class (AvailableState, ReservedState, CheckedInState) implements RoomState and defines transitions. Room delegates behaviour to current state", "Singleton pattern", "Command pattern"], ans: 1, exp: "State pattern: eliminates massive if/else. AvailableState.reserve() â†’ transitions to ReservedState. ReservedState.checkIn() â†’ CheckedInState. Adding a new state = new class. Room class stays clean." },
  { id: "oop195", diff: "scenario", topic: "Debug", q: "You're using a for-each loop over a collection and deleting elements inside the loop. You get ConcurrentModificationException. How do you fix it?", opts: ["Use a regular for loop", "Use Iterator explicitly and call iterator.remove() â€” the only safe way to remove elements during iteration without ConcurrentModificationException", "Use ArrayList instead", "Use removeAll()"], ans: 1, exp: "for-each uses the fail-fast iterator. Any structural modification (add/remove) via the Collection directly increments modCount, which the iterator checks â€” throws CME. Fix: Iterator<T> it = list.iterator(); while(it.hasNext()){ if(condition) it.remove(); }. Or use removeIf() (Java 8+)." },
  { id: "oop196", diff: "scenario", topic: "Design Problem", q: "You need a global configuration object accessible throughout the application, initialised once from a config file, thread-safe. Which pattern and implementation?", opts: ["Static class with public fields", "Singleton with Initialization-on-demand holder idiom: private static class Holder { static final Config INSTANCE = new Config(); } â€” thread-safe without synchronisation overhead, lazy initialisation", "A global variable", "A static utility class"], ans: 1, exp: "Initialization-on-demand holder: getInstance() returns Holder.INSTANCE. The Holder class is only loaded when getInstance() is first called (lazy). JVM class loading is thread-safe by specification â€” no synchronisation needed. Best practice for lazy, thread-safe Singleton." },
  { id: "oop197", diff: "scenario", topic: "Debug", q: "You have a class Animal with method makeSound(). Dog overrides it. You create Dog d = new Dog(); Animal a = d; then call a.makeSound(). Which version runs?", opts: ["Animal's makeSound()", "Dog's makeSound() â€” runtime polymorphism: the actual object type (Dog) determines which method runs, regardless of reference type (Animal)", "Both versions run", "Compile error"], ans: 1, exp: "Runtime polymorphism (dynamic dispatch): the JVM looks at the actual object type (Dog), not the reference type (Animal). Dog's makeSound() runs. This is the core of polymorphism â€” 'program to the interface, not the implementation.'" },
  { id: "oop198", diff: "scenario", topic: "Design Problem", q: "You're building a data access layer. Business logic classes directly instantiate DAO classes. This makes unit testing impossible (can't mock DBs). How do you fix it?", opts: ["Use static methods in DAO", "Apply Dependency Injection with DAO interfaces: business classes depend on IUserDao (interface), DAOs injected via constructor. Tests inject MockUserDao instead of real DB DAOs â€” fully testable", "Use Singleton DAO", "Add test flags in production code"], ans: 1, exp: "DI + Interface Segregation: business class receives IUserDao in constructor. Production: inject JdbcUserDao. Test: inject MockUserDao. No real DB needed in tests. Spring/Dagger manage injection in production. This is the Dependency Inversion Principle â€” depend on abstractions, not concretions." },
  { id: "oop199", diff: "scenario", topic: "Debug", q: "A Java program runs correctly single-threaded but produces wrong results with multiple threads accessing and modifying a shared object. The object uses no synchronisation. What OOP design helps?", opts: ["Use synchronized everywhere", "Make the shared object immutable â€” if its state cannot change after creation, threads can safely share it without synchronisation, eliminating race conditions. Or use thread-safe wrappers", "Use singleton", "Use volatile on all fields"], ans: 1, exp: "Immutability is the safest concurrency strategy. Immutable objects (final fields, no setters, defensive copies) can be shared freely between threads with no synchronisation overhead. For mutable state, use ConcurrentHashMap, AtomicInteger, or synchronized blocks." },
  { id: "oop200", diff: "scenario", topic: "Design Problem", q: "You need to add spell-check, grammar-check, and formatting as optional features to a text processor, where users can choose any combination. Class-based inheritance would cause an explosion of subclasses. Which pattern?", opts: ["Create all combination subclasses", "Decorator pattern: SpellCheckDecorator, GrammarDecorator, FormattingDecorator all extend TextProcessor. Combine: new SpellCheckDecorator(new GrammarDecorator(new FormattingDecorator(basicProcessor)))", "Abstract factory", "Composite pattern"], ans: 1, exp: "Decorator avoids class explosion: 3 features = 7 combination classes with inheritance vs 3 decorator classes. Attach/detach at runtime. Each decorator wraps and enhances the same interface. Java I/O is the canonical example." },
  { id: "oop201", diff: "scenario", topic: "Design Problem", q: "Your e-commerce app's Order class handles: persistence (SQL), email sending, PDF generation, and discount calculation â€” all in one class. What principle is violated and how do you refactor?", opts: ["Nothing is wrong", "Single Responsibility Principle: Order has too many reasons to change. Refactor: OrderRepository (persistence), EmailService (notifications), InvoiceGenerator (PDF), DiscountCalculator (pricing). Order only manages order data.", "Use inheritance", "Use static methods"], ans: 1, exp: "SRP: a class should have only one reason to change. If SQL schema changes, Order changes. If email template changes, Order changes. If discount rules change, Order changes. Extract: OrderRepository, NotificationService, InvoiceService, PricingEngine." },
  { id: "oop202", diff: "scenario", topic: "Debug", q: "You're using Java serialization. After changing a class (adding a field), deserialization of old data fails with InvalidClassException. How do you fix this?", opts: ["Don't add fields ever", "Declare a private static final long serialVersionUID in your class. This explicit UID persists across versions. Without it, Java auto-generates UID based on class structure â€” any change generates a new UID, making old data incompatible", "Use transient on all fields", "Recreate the file"], ans: 1, exp: "serialVersionUID: explicitly declare private static final long serialVersionUID = 1L; Java uses this to verify compatibility between serialized and current class versions. Without it: adding a field changes auto-generated UID â†’ InvalidClassException." },
  { id: "oop203", diff: "scenario", topic: "Design Problem", q: "You're building a plugin architecture where new plugins can be added without recompiling the core application. Each plugin implements a specific interface. How do OOP principles enable this?", opts: ["Hardcode all plugins", "Open/Closed Principle + interface programming: core depends only on PluginInterface. Plugins are separate JARs loaded at runtime via ServiceLoader or reflection, implementing the interface. Core never changes when new plugins are added", "Singleton pattern", "Abstract classes for each plugin type"], ans: 1, exp: "OCP + polymorphism + interface-based programming: core code is closed for modification, open for extension (new plugin = new JAR). java.util.ServiceLoader discovers implementations of a service interface from classpath." },
  { id: "oop204", diff: "scenario", topic: "Debug", q: "You define a method add(int a, int b) and add(double a, double b) (overloaded). When you call add(1, 2.0), which version is called?", opts: ["Compile error", "add(double, double): Java promotes int to double for the 2nd argument. Since one argument is already double, Java widens the int to double and calls the double version", "add(int, int)", "Ambiguous â€” runtime error"], ans: 1, exp: "Method resolution for overloading: Java prefers widening over boxing over varargs. int can be widened to double, so add(1, 2.0) â†’ add(double 1.0, double 2.0). Order: widening > boxing > varargs." },
  { id: "oop205", diff: "scenario", topic: "Design Problem", q: "You need to access a remote service (on another server) using the same interface as a local service, with network error handling and retries transparent to the caller. Which pattern?", opts: ["Direct HTTP calls everywhere", "Remote Proxy: RemoteServiceProxy implements the same interface as the local service, handles network communication, serialisation, retries, and error handling transparently. Client code calls the proxy exactly like a local object", "Adapter pattern", "Facade pattern"], ans: 1, exp: "Remote Proxy (RPC/RMI concept): client calls interface methods; proxy marshals parameters, sends over network, receives response, unmarshals result. Client is unaware of network details. Spring Feign Client is a modern REST proxy." },
  { id: "oop206", diff: "scenario", topic: "Debug", q: "You make an interface I with a default method m(). Class A implements I. Class B extends A. You call new B().m(). Which m() is called?", opts: ["Interface I's default m()", "A's m() if A overrides it, otherwise I's default m(). B inherits from A first (class over interface), then from I. Class implementations always take priority over interface defaults", "B gets compile error", "Ambiguous â€” runtime exception"], ans: 1, exp: "Resolution order: (1) class override wins over default method, (2) more specific interface default wins over less specific. So: if A overrides m() â†’ A's version is called (B inherits it). If A doesn't override â†’ I's default runs." },
  { id: "oop207", diff: "scenario", topic: "Design Problem", q: "You have 10 report types (SalesReport, InventoryReport, etc.), each needing to be exported to 3 formats (PDF, Excel, CSV). Which pattern avoids creating 30 classes?", opts: ["Create all 30 classes", "Visitor pattern OR Bridge pattern: Bridge separates Report (abstraction) from ExportFormat (implementation). SalesReport uses a PDF ExportFormat. 10 + 3 = 13 classes instead of 30. Adding a new format = 1 new class", "Strategy pattern only", "Template Method only"], ans: 1, exp: "Bridge pattern: decouple abstraction (Report types) from implementation (Export formats). Report has a reference to ExportFormat interface. 10 Report classes + 3 ExportFormat classes = 13. Combinations are composed at runtime." },
  { id: "oop208", diff: "scenario", topic: "Debug", q: "You create class B extends A. A has a constructor A(int x). You don't write any constructor in B. Does B compile?", opts: ["Yes, B uses A's constructor directly", "No â€” if A has no default no-arg constructor, B must explicitly call super(int x) in a constructor. Java doesn't automatically forward parameterised constructors to subclasses", "Yes, Java auto-generates super() calls with parameters", "Only if A is abstract"], ans: 1, exp: "If A has A(int x) but NO A() (no-arg), then Java's implicit super() in B's default constructor fails â€” A doesn't have a no-arg constructor. B must define a constructor and explicitly call super(someInt)." },
  { id: "oop209", diff: "scenario", topic: "Design Problem", q: "You need to guarantee that specific initialisation steps always happen in a particular order when creating objects of a class hierarchy. Which OOP feature helps?", opts: ["Static methods", "Constructor chaining with super(): Java enforces that the superclass constructor runs before the subclass constructor. Combined with Template Method in constructors (avoiding overrideable method calls), you can guarantee initialisation order", "Interfaces", "Abstract methods"], ans: 1, exp: "Constructor chaining (super()) guarantees parent initialisation before child. However, avoid calling overrideable methods in constructors (dynamic dispatch can call child's method before child fields initialise)." },
  { id: "oop210", diff: "scenario", topic: "Debug", q: "You call getClass() on an object and get 'class Dog', but the variable is declared as Animal. How do you explain this to a junior developer?", opts: ["It's a bug", "getClass() always returns the runtime class of the actual object (Dog), not the declared type of the variable (Animal). This is the fundamental nature of OOP â€” the object knows what it actually is, regardless of the reference type pointing to it", "Animal reference hides Dog's class", "Reflection error"], ans: 1, exp: "getClass() is a final method from Object that returns the actual runtime class. No matter what reference type you use (Animal, Object), the actual object was created as 'new Dog()' â€” getClass() returns Dog.class." },
  { id: "oop211", diff: "scenario", topic: "Design Problem", q: "Thread1 locks resource A then waits for B. Thread2 locks B then waits for A. Application freezes. What OOP design prevents this?", opts: ["Use more threads", "Deadlock prevention via consistent lock ordering â€” always acquire locks in the same order everywhere. Or use immutable objects (no locking needed), or compose behavior via message passing (actor model)", "Use synchronized on all methods", "Restart the JVM"], ans: 1, exp: "Deadlock prevention: 1) Lock ordering: always acquire locks in the same global order. 2) tryLock(timeout): give up if can't acquire. 3) Immutable objects: no shared mutable state = no locks needed. 4) ConcurrentHashMap, AtomicInteger instead of manual synchronisation." },
  { id: "oop212", diff: "scenario", topic: "Design Problem", q: "You need a type-safe heterogeneous container that can store objects of different types and retrieve them with full compile-time type safety. What OOP technique enables this?", opts: ["Use Object references with casting", "Type-safe heterogeneous container using Class<T> tokens as keys: Map<Class<?>, Object> map; <T> void put(Class<T> type, T value); <T> T get(Class<T> type). Josh Bloch's pattern from Effective Java", "Use instanceof for each type", "Use a wrapper class for each type"], ans: 1, exp: "Type-safe heterogeneous container (Effective Java Item 33): instead of Map<String, Object>, use Map<Class<?>, Object> where the key is the type token. put(String.class, 'hello'). get(String.class) returns a String without casting. The Class<T> token carries the type information safely." },
  { id: "oop213", diff: "scenario", topic: "Design Problem", q: "Your application generates complex objects (Orders, Reports, Invoices) and the creation logic is getting mixed with business logic. How do you cleanly separate object creation from usage?", opts: ["Put all creation in constructors", "Factory Method, Abstract Factory, or Builder pattern: creation logic is encapsulated in factory classes or builder objects. Business logic only uses the created objects, never 'new'. Follow the principle 'Tell, Don't Ask' and 'Dependency Inversion'", "Use Singleton for each type", "Use static factory methods only"], ans: 1, exp: "Separating creation from usage: 1) Factory classes encapsulate creation logic. 2) Dependency Injection: inject created objects. 3) Builder: for complex object construction. Business logic depends on interfaces (DIP), not 'new ConcreteClass()'. This makes code testable (inject mocks) and flexible (swap implementations)." },
  { id: "oop214", diff: "scenario", topic: "Debug", q: "You have a class with only static methods and a private constructor (utility class). A developer is trying to extend it. What problem does extending a utility class cause?", opts: ["No problem â€” it works fine", "Extending a utility class violates its design intent â€” instances of the subclass would expose an instance with no instance state. The public no-arg constructor in the subclass would call the private super() constructor â€” compile error. Make utility classes final to prevent extension", "Simply override the constructor", "Use abstract instead of final"], ans: 1, exp: "Utility classes (Math, Arrays, Collections) should be final with a private constructor: private UtilityClass() { throw new AssertionError(); }. This prevents: (1) instantiation, (2) extension (subclass would need to call super() which is private). Making it final explicitly communicates the design intent." },
  { id: "oop215", diff: "scenario", topic: "Design Problem", q: "You have a List<String> returned by a library method. You want to ensure the caller cannot modify the returned list. How do you enforce this with OOP?", opts: ["Return List<String> directly", "Return Collections.unmodifiableList(list) â€” a view that throws UnsupportedOperationException on any modification attempt. Or return List.copyOf(list) for an immutable copy (Java 10+). Or return an ImmutableList (Guava)", "Make the List final", "Return an array instead"], ans: 1, exp: "Defensive programming: Collections.unmodifiableList() wraps the list â€” any mutating operation throws UnsupportedOperationException at runtime. List.copyOf() creates a truly independent immutable copy. Best practice: return interfaces (List) not implementations, and wrap when mutation should be prevented." },
  { id: "oop216", diff: "scenario", topic: "Debug", q: "You have an interface with 5 methods. You implement it in 3 places, but each implementation only really uses 2-3 methods. The others have empty or stub bodies. What SOLID violation is this and how do you fix it?", opts: ["SRP violation", "ISP (Interface Segregation Principle) violation: the interface is too fat â€” clients are forced to depend on methods they don't use. Fix: split into 2-3 smaller, focused interfaces. Implementing classes implement only the interfaces they actually need", "DIP violation", "LSP violation"], ans: 1, exp: "ISP: one fat interface with 5 methods forces all implementors to know about all 5. Split: if methods A,B are about reading and C,D,E about writing, create ReadableInterface and WritableInterface. Implementations implement only what they use. No more stub bodies." },
  { id: "oop217", diff: "scenario", topic: "Design Problem", q: "A legacy class LegacyCalculator.compute(double[], String) must be used where your system expects Calculator.calculate(List<Double>). You cannot change either class. What pattern do you use?", opts: ["Just use instanceof and cast", "Adapter pattern: create LegacyCalculatorAdapter implementing Calculator. Internally: convert List<Double> to double[], call LegacyCalculator.compute(), map 'operation' String. Client code only sees Calculator interface", "Extend LegacyCalculator", "Use reflection to call the method"], ans: 1, exp: "Adapter Pattern: LegacyCalculatorAdapter implements Calculator { private LegacyCalculator legacy = new LegacyCalculator(); public double calculate(List<Double> values){ double[] arr = values.stream().mapToDouble(Double::doubleValue).toArray(); return legacy.compute(arr, 'sum'); } }. Client code unchanged. Legacy code unchanged." },
  { id: "oop218", diff: "scenario", topic: "Design Problem", q: "You need to build a report generation system where the report generation process is: fetch data â†’ format data â†’ render report. Each step can vary independently. Which OOP pattern best models this pipeline?", opts: ["One monolithic generateReport() method", "Strategy Pattern for each step: DataFetcher, DataFormatter, ReportRenderer interfaces with interchangeable implementations. ReportGenerator holds references to each strategy. Combine different strategies at runtime for different report types", "Template Method only", "Builder pattern"], ans: 1, exp: "Strategy pipeline: ReportGenerator(DataFetcher fetcher, DataFormatter formatter, ReportRenderer renderer). DatabaseFetcher, CsvFormatter, PdfRenderer as concrete strategies. A monthly PDF report: new ReportGenerator(new DatabaseFetcher(), new CsvFormatter(), new PdfRenderer()). Each step is independently replaceable (OCP)." },
  { id: "oop219", diff: "scenario", topic: "Debug", q: "A method returns an Animal reference but the caller needs Dog-specific methods. The caller uses (Dog) animal without instanceof. This works in testing but fails in production. Why and how do you fix this?", opts: ["It's a JVM bug", "ClassCastException: in production, the method returns a Cat or another Animal subtype, not a Dog. The unchecked cast fails. Fix: (1) Always check instanceof before casting, (2) Better: add the needed behavior to the Animal interface (polymorphism), (3) Use visitor pattern if behavior addition is impossible", "Use a try-catch for ClassCastException", "Use reflection to check the type"], ans: 1, exp: "ClassCastException is a runtime error from unsafe downcasting. Root cause: the caller is making assumptions about the concrete type. Fix polymorphically: if Dog has bark(), add speak() to Animal and override it in Dog. If you must cast: if (animal instanceof Dog dog) { dog.bark(); }. Avoid casts â€” they break polymorphism." },
  { id: "oop220", diff: "scenario", topic: "Design Problem", q: "You're designing a validation framework. An Order must pass multiple validation rules (total > 0, customer exists, items in stock). New rules will be added over time. How do you design this?", opts: ["Long if-else chain in a validate() method", "Chain of Responsibility or Specification Pattern: each rule is a Validator class implementing Validator.validate(Order order). Rules chain together or compose with and()/or(). New rule = new Validator class. Open/Closed Principle: no modification to existing validators", "Add validation in the Order constructor", "Use reflection to discover validation rules"], ans: 1, exp: "Chain of Responsibility: MinimumTotalValidator â†’ CustomerExistsValidator â†’ ItemsInStockValidator. Each validates and either returns an error or passes to next. Alternatively: Specification Pattern â€” compose rules: minTotal.and(customerExists).and(inStock). Adding a new rule = one new class, zero existing code changes (OCP)." },
];

